// Client-side protections (respects _protectionEnabled flag)
var _protectionEnabled = true;
var _devtoolsInterval = null;
function applyProtection(enabled) {
    _protectionEnabled = enabled;
    document.getElementById('settings-protection').checked = enabled;
    document.getElementById('protection-status').textContent = enabled ? 'ON' : 'OFF';
    document.getElementById('protection-status').style.color = enabled ? 'var(--success)' : 'var(--danger)';
}
document.addEventListener('contextmenu', function(e) { if (_protectionEnabled) e.preventDefault(); });
document.addEventListener('keydown', function(e) {
    if (!_protectionEnabled) return;
    if (e.key === 'F12' || (e.ctrlKey && e.shiftKey && ['I','J','C'].includes(e.key.toUpperCase())) || (e.ctrlKey && e.key.toUpperCase() === 'U')) {
        e.preventDefault();
    }
});
document.addEventListener('selectstart', function(e) { if (_protectionEnabled) e.preventDefault(); });
document.addEventListener('copy', function(e) { if (_protectionEnabled) e.preventDefault(); });
try { Object.defineProperty(document, 'onselectstart', { get: function() { return null; } }); } catch (e) {}
(function() {
    var devtoolsOpen = false;
    var threshold = 160;
    var check = function() {
        if (!_protectionEnabled) { devtoolsOpen = false; return; }
        var w = window.outerWidth - window.innerWidth;
        var h = window.outerHeight - window.innerHeight;
        var detected = w > threshold || h > threshold || (w === 0 && h === 0 && window.outerWidth > 0);
        if (detected && !devtoolsOpen) {
            devtoolsOpen = true;
            document.body.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#fff;"><div style="text-align:center;padding:40px;"><div style="font-size:64px;margin-bottom:16px;">🔒</div><h2>Developer Tools Detected</h2><p style="color:#64748b;margin-top:8px;">Please close Developer Tools to continue using this system.</p></div></div>';
        } else if (!detected) {
            devtoolsOpen = false;
        }
    };
    _devtoolsInterval = setInterval(check, 1000);
})();
async function setProtection() {
    var enabled = document.getElementById('settings-protection').checked;
    applyProtection(enabled);
    var branding = await dbGet('settings', 'branding') || { key: 'branding' };
    branding.protectionEnabled = enabled;
    await dbPut('settings', branding);
    showToast('Protection ' + (enabled ? 'ON' : 'OFF'));
}

async function initAuth() {
    try {
        const adminExists = await dbGet('users', 'admin');
        if (!adminExists) {
            const pwHash = await hashPassword('admin123');
            await dbPut('users', { username: 'admin', password: pwHash, name: 'Administrator', role: 'admin', createdAt: new Date().toISOString() });
        }
    } catch (e) { console.error('initAuth admin check failed:', e); }
    try { await loadBranding(); } catch (e) { console.error('initAuth loadBranding failed:', e); }
    try { await initAcademicCache(); } catch (e) { console.error('initAuth initAcademicCache failed:', e); }
    try { await checkAllAccountActivity(); } catch (e) { console.error('initAuth checkAllAccountActivity failed:', e); }
    try { await syncUserAccounts(); } catch (e) { console.error('initAuth syncUserAccounts failed:', e); }
    try {
        const session = sessionStorage.getItem('currentUser');
        if (session) {
            const user = JSON.parse(session);
            const dbUser = await dbGet('users', user.username);
            if (dbUser && dbUser.status !== 'locked') {
                sessionStorage.setItem('currentUser', JSON.stringify(dbUser));
                // Terms & Conditions check — version-aware
                const key = 'terms_accepted_' + (dbUser.username || dbUser.id);
                const brandingCheck = await dbGet('settings', 'branding');
                const currentVersion = brandingCheck && brandingCheck.termsContent ? (brandingCheck.termsVersion || 1) : 0;
                if (currentVersion > 0 && dbUser.termsVersion !== currentVersion) {
                    localStorage.removeItem(key);
                    showTermsModalApp(dbUser);
                    return;
                }
                if (localStorage.getItem(key) !== 'true') {
                    try {
                        const existing = await dbGet('users', dbUser.username || dbUser.id);
                        if (existing && existing.termsAccepted && existing.termsVersion === currentVersion) {
                            localStorage.setItem(key, 'true');
                        } else {
                            showTermsModalApp(dbUser);
                            return;
                        }
                    } catch {
                        showTermsModalApp(dbUser);
                        return;
                    }
                }
                return showApp(dbUser);
            }
        }
        document.getElementById('login-screen').style.display = 'flex';
        document.getElementById('app').style.display = 'none';
    } catch (e) { console.error('initAuth session check failed:', e); }
}
function staffRoleToSystemRole(staffRole) {
    const map = { admin: 'admin', lecturer: 'lecturer', professor: 'lecturer', dean: 'registrar', 'finance officer': 'finance', support: 'lecturer' };
    return map[(staffRole || '').toLowerCase()] || 'lecturer';
}
async function syncUserAccounts() {
    try {
        const batch = await dbGetBatch(['users','students','staff']);
        const allUsers = batch.users, students = batch.students, staffList = batch.staff;
        const created = [];
        for (const s of students) {
            if (s.status !== 'active' || !s.phone) continue;
            const hasUser = allUsers.some(u => u.studentId === s.id || u.username === s.phone);
            if (hasUser) continue;
            const pw = s.admissionNumber || s.id;
            const pwHash = await hashPassword(pw);
            allUsers.push({ username: s.phone, password: pwHash, name: s.name, role: 'student', status: 'active', studentId: s.id, createdAt: new Date().toISOString() });
            await dbPut('users', allUsers[allUsers.length - 1]);
            created.push('student:' + s.name + ' (' + s.phone + ')');
        }
        for (const st of staffList) {
            if (st.status !== 'active') continue;
            const username = st.email || st.phone || ('staff-' + st.id);
            const hasUser = allUsers.some(u => u.username === username || u.name === st.name);
            if (hasUser) continue;
            const pw = 'staff123';
            const pwHash = await hashPassword(pw);
            const role = staffRoleToSystemRole(st.role);
            allUsers.push({ username, password: pwHash, name: st.name, role, status: 'active', createdAt: new Date().toISOString() });
            await dbPut('users', allUsers[allUsers.length - 1]);
            created.push('staff:' + st.name + ' (' + username + ')');
        }
        if (created.length) console.log('SYNC: created ' + created.length + ' user accounts: ' + created.join(', '));
    } catch (err) {
        console.error('syncUserAccounts error:', err);
    }
}
async function login() {
    try {
        const input = sanitizeInput(document.getElementById('login-user').value.trim());
        const password = document.getElementById('login-pass').value;
        if (!input || !password) return showLoginError('Enter username and password');
        const res = await fetch('/api/login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ input, password })
        });
        const data = await res.json();
        if (!res.ok) {
            if (res.status === 401) return showLoginError('Invalid username or password');
            if (res.status === 403) return showLoginError(data.error || 'Access denied');
            return showLoginError('Login failed. Please try again.');
        }
        const user = data.user;
        if (!user) return showLoginError('Login failed');
        sessionStorage.setItem('currentUser', JSON.stringify(user));
        showLoginError('');
        document.getElementById('login-pass').value = '';
        var key = 'terms_accepted_' + (user.username || user.id);
        var brandingCheck = await dbGet('settings', 'branding');
        var currentVersion = brandingCheck && brandingCheck.termsContent ? (brandingCheck.termsVersion || 1) : 0;
        if (currentVersion > 0 && user.termsVersion !== currentVersion) {
            localStorage.removeItem(key);
            showTermsModalApp(user);
            return;
        }
        if (localStorage.getItem(key) !== 'true') {
            try {
                var existing = await dbGet('users', user.username || user.id);
                if (existing && existing.termsAccepted && existing.termsVersion === currentVersion) {
                    localStorage.setItem(key, 'true');
                } else {
                    showTermsModalApp(user);
                    return;
                }
            } catch (e) {
                showTermsModalApp(user);
                return;
            }
        }
        showApp(user);
        logAudit('login', 'user', { username: user.username });
    } catch (err) {
        showLoginError('Login failed. Please try again.');
        console.error('Login error:', err);
    }
}
window.login = login;
