async function saveBrochureDesign() {
    const d = {
        title: document.getElementById('br-title').value,
        subtitle: document.getElementById('br-subtitle').value,
        year: document.getElementById('br-year').value,
        panel1: document.getElementById('br-panel1').value,
        panel2: document.getElementById('br-panel2').value,
        panel4: document.getElementById('br-panel4').value,
        panel5: document.getElementById('br-panel5').value,
        panel6: document.getElementById('br-panel6').value,
        color: document.getElementById('brochure-color').value,
        footer1: document.getElementById('br-footer1').value
    };
    await dbSet('settings', 'brochureDesign', d);
    showToast('Brochure design saved!');
}
function previewBrochure() {
    const title = document.getElementById('br-title').value;
    const subtitle = document.getElementById('br-subtitle').value;
    const year = document.getElementById('br-year').value;
    const panel1 = document.getElementById('br-panel1').value;
    const panel2 = document.getElementById('br-panel2').value;
    const panel4 = document.getElementById('br-panel4').value;
    const panel5 = document.getElementById('br-panel5').value;
    const panel6 = document.getElementById('br-panel6').value;
    const color = document.getElementById('brochure-color').value;
    const footer1 = document.getElementById('br-footer1').value;
    closeModal();
    const html = renderBrochureHtml(title, subtitle, year, panel1, panel2, panel4, panel5, panel6, color, footer1);
    showModal('Brochure Preview — Side 1 (Front)',
        `<div style="max-height:80vh;overflow:auto;display:flex;flex-direction:column;align-items:center;gap:16px;">
            <div style="width:297mm;transform:scale(0.5);transform-origin:top center;flex-shrink:0;">${html.side1}</div>
            <div style="font-size:10px;color:var(--text-muted);">⬇ Scroll down for Side 2 (Back) ⬇</div>
            <div style="width:297mm;transform:scale(0.5);transform-origin:top center;flex-shrink:0;">${html.side2}</div>
        </div>`,
        `<button class="btn btn-success" onclick="printBrochure()">🖨️ Print Both Sides</button>`
    );
}
function printBrochure() {
    const el1 = document.getElementById('brochure-side1') || document.querySelector('#brochure-side1');
    const el2 = document.getElementById('brochure-side2') || document.querySelector('#brochure-side2');
    if (!el1 || !el2) { showToast('Preview the brochure first'); return; }
    const w = window.open('', '_blank', 'width=800,height=600');
    w.document.write('<html><head><title>Brochure</title><style>'
        + 'body{font-family:Arial,sans-serif;margin:0;padding:0;background:#f5f5f5;}'
        + '.brochure-page{width:297mm;height:210mm;overflow:hidden;margin:0 auto;background:#fff;position:relative;page-break-after:always;}'
        + '*{-webkit-print-color-adjust:exact;print-color-adjust:exact;}'
        + '@page{size:A4 landscape;margin:0;}'
        + '@media print{body{background:#fff;}.brochure-page{page-break-after:always;}}'
        + '</style></head><body>'
        + '<div class="brochure-page">' + el1.outerHTML + '</div>'
        + '<div class="brochure-page">' + el2.outerHTML + '</div>'
        + '</body></html>');
    w.document.close();
    w.print();
}
function renderBrochureHtml(title, subtitle, year, panel1, panel2, panel4, panel5, panel6, color, footer1) {
    const gold = '#d4a843';
    const panelStyle = (isCover) =>
        `width:99mm;height:210mm;overflow:hidden;box-sizing:border-box;display:flex;flex-direction:column;${isCover ? '' : 'border-right:1px dashed ' + color + '44;'}`;
    function coverPanel() {
        return `<div style="${panelStyle(true)};background:linear-gradient(160deg,${color},${color}dd);color:#fff;padding:14px 10px;text-align:center;justify-content:center;align-items:center;">
            <div style="position:absolute;top:4px;left:4px;right:4px;height:40px;background:radial-gradient(ellipse at 50% 0,${gold}33,transparent 70%);"></div>
            <div style="font-size:22px;font-weight:900;letter-spacing:1px;text-shadow:0 1px 6px rgba(0,0,0,0.2);">${title}</div>
            <div style="margin:6px auto;width:50px;height:1px;background:${gold};"></div>
            <div style="font-size:10px;letter-spacing:1px;opacity:0.9;padding:0 4px;">${subtitle}</div>
            <div style="margin-top:8px;font-size:8px;opacity:0.7;">✦ Graduation ${year} ✦</div>
        </div>`;
    }
    function infoPanel(icon, heading, text) {
        return `<div style="${panelStyle(false)};background:#fff;padding:12px 8px;justify-content:flex-start;">
            <div style="width:28px;height:28px;border-radius:50%;background:${color};color:#fff;display:flex;align-items:center;justify-content:center;font-size:14px;margin-bottom:6px;flex-shrink:0;">${icon}</div>
            <div style="font-weight:700;color:${color};font-size:10px;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;flex-shrink:0;">${heading}</div>
            <div style="font-size:8.5px;color:#475569;line-height:1.5;overflow:hidden;word-wrap:break-word;">${text}</div>
        </div>`;
    }
    function backCoverPanel(text) {
        return `<div style="${panelStyle(true)};background:${color};color:#fff;padding:14px 8px;text-align:center;justify-content:center;align-items:center;">
            <div style="font-size:9px;line-height:1.5;opacity:0.9;font-style:italic;">${text}</div>
            <div style="margin-top:6px;font-size:6px;opacity:0.5;">${title} — ${footer1}</div>
        </div>`;
    }
    const side1 = `<div id="brochure-side1" style="display:flex;width:297mm;height:210mm;background:#fff;font-family:'Segoe UI',Arial,sans-serif;">
        ${infoPanel('✿', 'Welcome', panel1)}
        ${infoPanel('◆', 'Programs', panel2)}
        ${coverPanel()}
    </div>`;
    const side2 = `<div id="brochure-side2" style="display:flex;width:297mm;height:210mm;background:#fff;font-family:'Segoe UI',Arial,sans-serif;">
        ${infoPanel('✦', 'Highlights', panel4)}
        ${infoPanel('✉', 'Contact', panel5)}
        ${backCoverPanel(panel6)}
    </div>`;
    return { side1, side2 };
}
