async function backupData() {
    const stores = ['settings','students','courses','enrollments','attendance','chapel','grades','staff','payments','feeStructure','installments','exams','seating','books','borrows','events','hostels','alumni','inventory','certificates','whatsappLog','campuses','studyCenters','gradRequirements','whatsappTemplates','users','audit','idCards','counters','lessons','notes','questionBank','quizzes','quizRegistrations','submissions','alerts','tickets','lessonFiles','expenseCategories','expenses','incomeCategories','income','mpesaTransactions'];
    const data = { version: 12, date: new Date().toISOString() };
    for (const store of stores) data[store] = await dbGetAll(store);
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'college_backup_' + new Date().toISOString().split('T')[0] + '.json'; a.click();
    showToast('Backup downloaded!'); logAudit('exported', 'backup', { date: data.date });
}
async function restoreData(event) {
    const file = event.target.files[0]; if (!file) return;
    if (!await showConfirm('Confirm', 'This will REPLACE all existing data. Continue?')) return;
    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const data = JSON.parse(e.target.result);
            const stores = ['settings','students','courses','enrollments','attendance','chapel','grades','staff','payments','feeStructure','installments','exams','seating','books','borrows','events','hostels','alumni','inventory','certificates','whatsappLog','campuses','studyCenters','gradRequirements','whatsappTemplates','users','audit','idCards','counters','lessons','notes','questionBank','quizzes','quizRegistrations','submissions','alerts','tickets','lessonFiles','expenseCategories','expenses','incomeCategories','income','mpesaTransactions'];
            for (const store of stores) { await dbClear(store); if (data[store]) for (const item of data[store]) await dbPut(store, item); }
            await init(); showToast('Data restored successfully!'); logAudit('restored', 'backup', { date: data.date });
        } catch (err) { showToast('Invalid backup file!'); }
    };
    reader.readAsText(file);
}
async function clearAllData() {
    if (!await showConfirm('Confirm', 'DELETE ALL DATA? This is permanent!')) return;
    if (!await showConfirm('Confirm', 'Are you absolutely sure?')) return;
    const stores = ['students','courses','enrollments','attendance','chapel','grades','staff','payments','feeStructure','installments','exams','seating','books','borrows','events','hostels','alumni','inventory','certificates','whatsappLog','campuses','studyCenters','gradRequirements','whatsappTemplates','users','audit','idCards','counters','lessons','notes','questionBank','quizzes','quizRegistrations','submissions','alerts','tickets','lessonFiles','expenseCategories','expenses','incomeCategories','income','mpesaTransactions'];
    for (const store of stores) await dbClear(store);
    await init(); showToast('All data cleared'); logAudit('cleared', 'all-data', {});
}
async function migrateIndexedDB() {
    if (!await showConfirm('Migrate', 'This will copy all data from your browser storage (IndexedDB) to the server. Continue?')) return;
    if (!await showConfirm('Important', 'Run this only once from the PC where you originally entered data!\n\n⚠ Backup your data first with the Backup button.\n\nProceed?')) return;
    try {
        const stores = ['settings','students','courses','enrollments','attendance','chapel','grades','staff','payments','feeStructure','installments','exams','seating','books','borrows','events','hostels','alumni','inventory','certificates','whatsappLog','campuses','studyCenters','gradRequirements','whatsappTemplates','users','audit','idCards','counters','lessons','notes','questionBank','quizzes','quizRegistrations','submissions','alerts','tickets','lessonFiles','expenseCategories','expenses','incomeCategories','income','mpesaTransactions'];
        const db = await new Promise((resolve, reject) => {
            const r = indexedDB.open('CollegeManagementDB');
            r.onsuccess = e => resolve(e.target.result);
            r.onerror = e => reject(e.target.error);
        });
        let total = 0;
        for (const storeName of stores) {
            if (!db.objectStoreNames.contains(storeName)) continue;
            const records = await new Promise((resolve, reject) => {
                const tx = db.transaction(storeName, 'readonly');
                const req = tx.objectStore(storeName).getAll();
                req.onsuccess = () => resolve(req.result);
                req.onerror = () => reject(req.error);
            });
            for (const record of records) {
                await dbPut(storeName, record);
                total++;
            }
        }
        db.close();
        showToast(`Migration complete! ${total} records copied to server.`, { type: 'success', duration: 6000 });
        await init();
    } catch (e) {
        if (e.name === 'SecurityError' || e.message?.includes('user denied permission')) {
            showToast('Browser blocked IndexedDB. Use Firefox or access via localhost (127.0.0.1).', { type: 'danger' });
        } else {
            showToast('Migration failed: ' + e.message, { type: 'danger' });
        }
    }
}
