async function showStudyCenterForm(center = null) {
    const isEdit = !!center;
    const content = `<input type="hidden" id="sc-edit-id" value="${center ? center.id : ''}">
<div class="form-group"><label>Center Name *</label><input type="text" id="sc-name" value="${center ? center.name : ''}" placeholder="e.g., Kitale Net Study Center" oninput="suggestSCCode()"></div>
<div class="form-group"><label>Center Code * (short, used in admission numbers)</label><input type="text" id="sc-code" value="${center ? center.code : ''}" placeholder="e.g., KNSC" maxlength="8" style="text-transform:uppercase;font-weight:600;letter-spacing:1px;" oninput="updateSCAdmissionPreview()"><div id="sc-code-suggestion" style="margin-top:4px;font-size:11px;color:var(--text-muted);"></div><div style="font-size:10px;color:var(--text-muted);margin-top:4px;">ⓘ This <b>short code</b> (not the full name) is what appears in admission numbers like <b>EMA/KNSC/1-26/001</b>. Maximum 8 characters.</div></div>
<div class="form-group"><label>Address</label><input type="text" id="sc-address" value="${center ? center.address || '' : ''}"></div>
<div class="form-group"><label>Region</label><select id="sc-region"><option value="">No region</option></select></div>
<div class="form-group"><label>Admission Number Preview</label><div style="font-size:10px;color:var(--text-muted);margin-bottom:4px;">Format: <b>SCHOOL-INITIALS / [CENTER CODE] / MONTH-YEAR / SEQ</b></div><div id="sc-adm-preview" style="padding:12px;background:var(--bg-input);border-radius:var(--radius);font-weight:700;color:var(--accent);font-size:18px;text-align:center;letter-spacing:0.5px;"></div><div id="sc-adm-preview-detail" style="font-size:10px;color:var(--text-muted);margin-top:4px;text-align:center;"></div></div>`;
    showModal(isEdit ? 'Edit Study Center' : 'Add Study Center', content, `<button class="btn btn-primary" onclick="saveStudyCenter()">${isEdit ? 'Update' : 'Save'}</button>`);
    (async () => {
        if (!window._regionsCache) window._regionsCache = await dbGetAll('regions').catch(() => []);
        const sel = document.getElementById('sc-region');
        if (sel) {
            sel.innerHTML = '<option value="">No region</option>' + window._regionsCache.map(r => `<option value="${r.id}" ${center && center.regionId === r.id ? 'selected' : ''}>${r.name}</option>`).join('');
        }
    })();
    const nameEl = document.getElementById('sc-name');
    if (nameEl) {
        nameEl.oninput = suggestSCCode;
        nameEl.addEventListener('focus', suggestSCCode);
    }
    const codeEl = document.getElementById('sc-code');
    if (codeEl) {
        codeEl.addEventListener('input', () => {
            codeEl.value = codeEl.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
            updateSCAdmissionPreview();
        });
    }
    updateSCAdmissionPreview();
}
function suggestSCCode() {
    const name = document.getElementById('sc-name').value.trim();
    const editId = document.getElementById('sc-edit-id').value;
    const codeInput = document.getElementById('sc-code');
    if (editId && codeInput.value) return;
    let suggested = '';
    if (name) {
        const words = name.split(/\s+/).filter(w => w.length > 0);
        if (words.length >= 3) {
            suggested = words.map(w => w[0]).join('').toUpperCase().substring(0, 5);
        } else if (words.length === 2) {
            suggested = (words[0].substring(0, 2) + words[1].substring(0, 2)).toUpperCase();
        } else if (words.length === 1) {
            suggested = words[0].substring(0, 4).toUpperCase();
        }
    }
    codeInput.value = suggested;
    document.getElementById('sc-code-suggestion').textContent = suggested ? 'Suggested: ' + suggested : '';
    updateSCAdmissionPreview();
}
async function updateSCAdmissionPreview() {
    const branding = await dbGet('settings', 'branding');
    const initials = (branding && branding.initials) ? branding.initials : 'XX';
    const codeInput = document.getElementById('sc-code');
    const code = codeInput ? (codeInput.value || 'XXXX').toUpperCase() : 'XXXX';
    const nameInput = document.getElementById('sc-name');
    const name = nameInput ? nameInput.value : '';
    const now = new Date();
    const month = now.getMonth() + 1;
    const year = String(now.getFullYear()).slice(-2);
    const el = document.getElementById('sc-adm-preview');
    if (el) el.textContent = `${initials}/${code}/${month}-${year}/001`;
    const detail = document.getElementById('sc-adm-preview-detail');
    if (detail) {
        const codeIsValid = code && code !== 'XXXX' && code.length <= 8;
        if (!codeIsValid) {
            detail.innerHTML = '<span style="color:var(--danger);">⚠ Please enter a short center code (max 8 chars) — full name is not used in admission numbers.</span>';
        } else {
            let _sv = 0;
            try { const _s = await dbGet('settings', 'admissionLastSeq'); if (_s && typeof _s.value === 'number') _sv = _s.value; } catch (e) {}
            const _me = await getMaxExistingAdmissionSeq();
            const _seq = Math.max(_sv, _me) + 1;
            const seqStr = String(_seq).padStart(3, '0');
            detail.innerHTML = `Next: <b>${initials}/${code}/${month}-${year}/${seqStr}</b> — center: <i>${name || '(unnamed)'}</i>`;
        }
    }
}
async function saveStudyCenter() {
    const name = document.getElementById('sc-name').value.trim();
    let code = document.getElementById('sc-code').value.trim().toUpperCase().replace(/[^A-Z0-9]/g, '');
    if (!name) return showToast('Name required!');
    if (!code) return showToast('Code required! Use a short alphanumeric code (max 8 chars).');
    if (code.length > 8) return showToast('Code too long! Maximum 8 characters. Use a short code, not the full center name.');
    if (code.length < 2) return showToast('Code too short! Use at least 2 characters.');
    if (code.toLowerCase() === name.toLowerCase().replace(/\s+/g, '')) {
        return showToast('Code cannot be the same as the center name. Please use a short abbreviation.');
    }
    const editId = document.getElementById('sc-edit-id').value;
    const id = editId || 'SC-' + code;
    const center = { id, name, code, address: document.getElementById('sc-address').value.trim(), regionId: document.getElementById('sc-region').value || '', createdAt: editId ? (await dbGet('studyCenters', id)).createdAt : new Date().toISOString() };
    await dbPut('studyCenters', center); closeModal(); renderStudyCenters(); showToast(editId ? 'Study Center updated!' : 'Study Center added!'); logAudit(editId ? 'updated' : 'created', 'study-center', center);
}
async function editStudyCenter(id) { const c = await dbGet('studyCenters', id); if (!c) return; showStudyCenterForm(c); }
async function deleteStudyCenter(id) { if (!await showConfirm('Confirm', 'Delete study center?')) return; await dbDelete('studyCenters', id); renderStudyCenters(); showToast('Study center deleted'); logAudit('deleted', 'study-center', { id }); }
async function renderUsers() {
    const users = await dbGetAll('users');
    const auditFilter = document.getElementById('audit-user');
    const students = await dbGetAll('students');
    const searchEl = document.getElementById('users-search');
    const q = searchEl ? searchEl.value.toLowerCase().trim() : '';
    const filtered = q ? users.filter(u =>
        (u.name || '').toLowerCase().includes(q) ||
        (u.username || '').toLowerCase().includes(q) ||
        (u.role || '').toLowerCase().includes(q) ||
        u.studentId === q
    ) : users;
    const activeUsers = filtered.filter(u => u.status !== 'locked');
    const lockedUsers = filtered.filter(u => u.status === 'locked');
    let html = '';
    if (lockedUsers.length) {
        html += `<div style="font-size:10px;font-weight:700;text-transform:uppercase;color:var(--danger);letter-spacing:1px;margin-bottom:6px;">🔒 Locked Accounts (${lockedUsers.length})</div>`;
        html += lockedUsers.map(u => {
            const daysLocked = u.lockedAt ? countWorkingDays(u.lockedAt, new Date()) : '—';
            return `<div class="event-item" style="border-left:3px solid var(--danger);padding-left:8px;"><div><b>${u.username}</b> <span class="badge badge-danger">Locked</span><br><span style="font-size:11px;color:var(--text-muted);">${u.name || ''} — ${u.lockedReason || 'Inactive'} — Locked: ${formatDate(u.lockedAt)} (${daysLocked} working days)</span></div><div style="display:flex;gap:4px;"><button class="btn btn-success btn-sm" onclick="reactivateUser('${u.username}')">Reactivate</button> <button class="btn btn-danger btn-sm" onclick="deleteUser('${u.username}')">Del</button></div></div>`;
        }).join('');
        html += '<div style="border-top:1px solid var(--border);margin:10px 0;"></div>';
    }
    html += activeUsers.map(u => {
        let statusBadge = `<span class="badge badge-${getRoleColor(u.role)}">${u.role}</span>`;
        let extraInfo = '';
        if (u.role === 'student') {
            const student = students.find(s => s.id === u.studentId || s.id === u.username);
            if (u.lastLogin) {
                const days = countWorkingDays(u.lastLogin, new Date());
                const color = days >= 20 ? 'var(--danger)' : days >= 10 ? 'var(--warning)' : 'var(--text-muted)';
                extraInfo = `<br><span style="font-size:10px;color:${color};">Last login: ${formatDate(u.lastLogin)} (${days} working days ago)`;
                if (u.warned1 && !u.warned2) extraInfo += ' — ⚠️ Warning sent';
                if (u.warned2) extraInfo += ' — 🔒 Final warning sent';
                extraInfo += '</span>';
            }
            if (student && student.status !== 'active') {
                statusBadge += ` <span class="badge badge-warning">${student.status}</span>`;
            }
        }
        let regionInfo = '';
        if (u.role === 'coordinator' && u.regionId) {
            const r = window._regionsCache ? window._regionsCache.find(rr => rr.id === u.regionId) : null;
            regionInfo = `<br><span style="font-size:10px;color:var(--warning);">Region: ${r ? r.name : u.regionId}</span>`;
        }
        return `<div class="event-item"><div><b>${u.username}</b> ${statusBadge}${regionInfo}${extraInfo}</div>${u.username === 'admin' ? '' : `<button class="btn btn-outline btn-sm" onclick="resetUserPassword('${u.username}')">🔑 Pwd</button> <button class="btn btn-danger btn-sm" onclick="deleteUser('${u.username}')">Del</button>`}</div>`;
    }).join('');
    document.getElementById('users-list').innerHTML = html || `<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:10px;">${q ? 'No users match "' + q + '"' : 'No users'}</div>`;
    if (auditFilter) auditFilter.innerHTML = '<option value="">All Users</option>' + users.map(u => `<option value="${u.username}">${u.username}</option>`).join('');
}
