let smartSearchIndex = -1;
let smartSearchActiveItems = [];
async function performSmartSearch(query) {
    if (!query || query.length < 2) {
        document.getElementById('smart-search-results').classList.remove('active');
        return;
    }
    const q = query.toLowerCase();
    const results = [];
    const students = await dbGetAll('students');
    const matches = students.filter(s => s.name.toLowerCase().includes(q) || (s.admissionNumber || '').toLowerCase().includes(q) || (s.email || '').toLowerCase().includes(q) || (s.phone || '').includes(q) || (s.program || '').toLowerCase().includes(q));
    if (matches.length) results.push({ category: 'Students', items: matches.slice(0, 5).map(s => ({ label: 'Student', text: s.name, sub: `${s.admissionNumber || s.id} — ${s.program || 'No program'} — ${s.status}`, action: () => { showScreen('students'); closeModal(); }, })) });
    const courses = await dbGetAll('courses');
    const cMatches = courses.filter(c => c.name.toLowerCase().includes(q) || (c.code || '').toLowerCase().includes(q) || (c.department || '').toLowerCase().includes(q));
    if (cMatches.length) results.push({ category: 'Courses', items: cMatches.slice(0, 5).map(c => ({ label: 'Course', text: c.name, sub: `${c.code || ''} — ${c.department || ''} — ${c.credits || 0} credits`, action: () => { showScreen('courses'); }, })) });
    const staff = await dbGetAll('staff');
    const sMatches = staff.filter(s => s.name.toLowerCase().includes(q) || (s.role || '').toLowerCase().includes(q) || (s.department || '').toLowerCase().includes(q));
    if (sMatches.length) results.push({ category: 'Staff', items: sMatches.slice(0, 5).map(s => ({ label: 'Staff', text: s.name, sub: `${s.role || ''} — ${s.department || ''}`, action: () => { showScreen('staff'); }, })) });
    const quizzes = await dbGetAll('quizzes');
    const qzMatches = quizzes.filter(z => z.title.toLowerCase().includes(q) || (z.courseId || '').toLowerCase().includes(q));
    if (qzMatches.length) results.push({ category: 'Quizzes', items: qzMatches.slice(0, 5).map(z => { const isStudentRole = JSON.parse(sessionStorage.getItem('currentUser') || '{}').role === 'student'; return { label: 'Quiz', text: z.title, sub: `Pass: ${z.passMark}% — ${z.questions ? z.questions.length : 0} questions`, action: isStudentRole ? () => { closeModal(); startQuiz(z.id); } : () => showScreen('quizzes') }; }) });
    const notes = await dbGetAll('notes');
    const nMatches = notes.filter(n => n.title.toLowerCase().includes(q) || (n.content || '').toLowerCase().includes(q));
    if (nMatches.length) results.push({ category: 'Notes', items: nMatches.slice(0, 5).map(n => ({ label: 'Note', text: n.title, sub: (n.content || '').substring(0, 60) + '...', action: () => { showScreen('notes'); }, })) });
    const lessons = await dbGetAll('lessons');
    const lMatches = lessons.filter(l => l.title.toLowerCase().includes(q) || (l.description || '').toLowerCase().includes(q));
    if (lMatches.length) results.push({ category: 'Lessons', items: lMatches.slice(0, 5).map(l => ({ label: 'Lesson', text: l.title, sub: (l.description || '').substring(0, 60) + '...', action: () => { showScreen('lessons'); }, })) });
    const lessonFiles = await dbGetAll('lessonFiles');
    const fMatches = lessonFiles.filter(f => f.fileName.toLowerCase().includes(q));
    if (fMatches.length) results.push({ category: 'Files', items: fMatches.slice(0, 5).map(f => ({ label: 'File', text: f.fileName, sub: 'Lesson resource', action: () => { showScreen('lessons'); }, })) });
    const payments = await dbGetAll('payments');
    const pMatches = payments.filter(p => (p.receiptNo || '').toLowerCase().includes(q) || (p.method || '').toLowerCase().includes(q));
    if (pMatches.length) results.push({ category: 'Payments', items: pMatches.slice(0, 5).map(p => ({ label: 'Payment', text: p.receiptNo, sub: `${formatCurrency(p.amount)} — ${p.method} — ${p.date}`, action: () => { showScreen('finance'); }, })) });
    renderSmartSearchResults(results);
}
function renderSmartSearchResults(results) {
    const container = document.getElementById('smart-search-results');
    if (!results.length) {
        container.innerHTML = '<div class="smart-search-empty">No results found</div>';
        container.classList.add('active');
        return;
    }
    smartSearchActiveItems = [];
    let html = '';
    for (const group of results) {
        html += `<div class="smart-search-category">${group.category} (${group.items.length})</div>`;
        for (const item of group.items) {
            smartSearchActiveItems.push(item);
            html += `<div class="smart-search-item" onclick="smartSearchNav(${smartSearchActiveItems.length - 1})"><div class="search-item-label">${item.label}</div><div class="search-item-text">${item.text}</div><div class="search-item-sub">${item.sub}</div></div>`;
        }
    }
    container.innerHTML = html;
    container.classList.add('active');
    smartSearchIndex = -1;
}
function smartSearchNav(index) {
    if (index >= 0 && index < smartSearchActiveItems.length) {
        smartSearchActiveItems[index].action();
        document.getElementById('smart-search').value = '';
        document.getElementById('smart-search-results').classList.remove('active');
        smartSearchActiveItems = [];
        smartSearchIndex = -1;
    }
}
function initSmartSearch() {
    const input = document.getElementById('smart-search');
    if (!input) return;
    input.addEventListener('input', (e) => {
        clearTimeout(input._searchTimeout);
        input._searchTimeout = setTimeout(() => performSmartSearch(e.target.value), 200);
    });
    input.addEventListener('keydown', (e) => {
        if (!document.getElementById('smart-search-results').classList.contains('active')) return;
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            smartSearchIndex = Math.min(smartSearchIndex + 1, smartSearchActiveItems.length - 1);
            highlightSearchItem();
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            smartSearchIndex = Math.max(smartSearchIndex - 1, 0);
            highlightSearchItem();
        } else if (e.key === 'Enter' && smartSearchIndex >= 0) {
            e.preventDefault();
            smartSearchNav(smartSearchIndex);
        } else if (e.key === 'Escape') {
            document.getElementById('smart-search-results').classList.remove('active');
        }
    });
    document.addEventListener('click', (e) => {
        if (!e.target.closest('.smart-search-container')) {
            document.getElementById('smart-search-results').classList.remove('active');
        }
    });
    document.addEventListener('keydown', (e) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
            e.preventDefault();
            input.focus();
            input.select();
        }
    });
}
function highlightSearchItem() {
    document.querySelectorAll('.smart-search-item').forEach((el, idx) => {
        el.classList.toggle('active', idx === smartSearchIndex);
    });
}

async function exportStudentsCSV() {
    const students = await dbGetAll('students');
    const payments = await dbGetAll('payments');
    const centers = await dbGetAll('studyCenters');
    let csv = 'Admission #,Name,Email,Phone,Program,Year,Study Center,Status,Fee Amount,Paid,Balance,Enroll Date\n';
    students.forEach(s => {
        const paid = payments.filter(p => p.studentId === s.id).reduce((sum, p) => sum + p.amount, 0);
        const sFee = getCachedStudentFee(s);
        const balance = sFee - paid;
        const center = centers.find(c => c.id === s.studyCenterId);
        csv += `"${s.admissionNumber || s.id}","${s.name}","${s.email || ''}","${s.phone || ''}","${s.program || ''}",${s.year || 1},"${center ? center.name : 'Main'}","${s.status}",${sFee},${paid},${balance},"${s.enrollDate}"\n`;
    });
    const blob = new Blob([csv], { type: 'text/csv' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'students_' + new Date().toISOString().split('T')[0] + '.csv'; a.click();
    showToast('Students exported!'); logAudit('exported', 'students-csv', {});
}
async function exportGradesPDF() {
    const grades = await dbGetAll('grades');
    const students = await dbGetAll('students');
    const courses = await dbGetAll('courses');
    const branding = await dbGet('settings', 'branding');
    const schoolName = branding ? branding.schoolName : 'College Management System';
    if (!grades.length) return showToast('No grades to export!');
    let html = `<html><head><title>Grades Report</title><style>body{font-family:Arial,sans-serif;padding:40px;}h1{color:#1e40af;margin-bottom:4px;}.subtitle{color:#64748b;margin-bottom:20px;}table{width:100%;border-collapse:collapse;margin:16px 0;font-size:12px;}th,td{border:1px solid #ddd;padding:6px 8px;text-align:left;}th{background:#020617;color:#f59e0b;}.section{margin:20px 0;}h2{font-size:14px;color:#1e40af;border-bottom:2px solid #f59e0b;padding-bottom:4px;}@media print{body{padding:0;}}</style></head><body>`;
    html += `<h1>${schoolName}</h1><p class="subtitle">Grades Report - Generated ${new Date().toLocaleDateString()}</p>`;
    const grouped = {};
    grades.forEach(g => { const key = `${g.studentId}-S${g.semester}`; if (!grouped[key]) grouped[key] = { studentId: g.studentId, semester: g.semester, grades: [] }; grouped[key].grades.push(g); });
    for (const key in grouped) {
        const group = grouped[key];
        const student = students.find(s => s.id === group.studentId);
        html += `<div class="section"><h2>${student ? student.name : group.studentId} - Semester ${group.semester}</h2>`;
        html += `<table><thead><tr><th>Course</th><th>Code</th><th>Credits</th><th>Score</th><th>Grade</th><th>GPA</th></tr></thead><tbody>`;
        let totalPoints = 0, totalCredits = 0;
        group.grades.forEach(g => {
            const c = courses.find(c => c.id === g.courseId);
            const credits = c ? c.credits : 3;
            totalPoints += g.gpa * credits; totalCredits += credits;
            html += `<tr><td>${c ? c.name : g.courseId}</td><td>${c ? c.code : ''}</td><td>${credits}</td><td>${g.score}</td><td><b>${g.grade}</b></td><td>${g.gpa}</td></tr>`;
        });
        const cgpa = totalCredits > 0 ? (totalPoints / totalCredits).toFixed(2) : '0.00';
        html += `</tbody></table><p style="text-align:right;"><b>GPA: ${cgpa}</b></p></div>`;
    }
    html += '</body></html>';
    const w = window.open('', '', 'width=800,height=600');
    w.document.write(html); w.document.close(); setTimeout(() => w.print(), 500);
}

function onStatementTypeChange() {
    const type = document.getElementById('stmt-type').value;
    document.getElementById('stmt-student-select').style.display = type === 'fee' ? 'flex' : 'none';
    if (type === 'fee') populateStatementStudents();
}
async function populateStatementStudents() {
    const students = await dbGetAll('students');
    const sel = document.getElementById('stmt-student');
    sel.innerHTML = '<option value="">Select student...</option>' + students.filter(s => s.status === 'active').map(s => `<option value="${s.id}">${escapeHtml(s.name)} ${s.admissionNumber ? '(' + escapeHtml(s.admissionNumber) + ')' : ''}</option>`).join('');
}
function generateStatement() {
    const type = document.getElementById('stmt-type').value;
    const fromDate = document.getElementById('stmt-from').value;
    const toDate = document.getElementById('stmt-to').value;
    if (!fromDate || !toDate) return showToast('Select a date range!');
    if (type === 'fee') {
        const studentId = document.getElementById('stmt-student').value;
        if (!studentId) return showToast('Select a student!');
        generateFeeStatement(studentId, fromDate, toDate);
    } else if (type === 'income') {
        generateIncomeStatement(fromDate, toDate);
    } else if (type === 'expense') {
        generateExpenseStatement(fromDate, toDate);
    } else if (type === 'summary') {
        generateSummaryStatement(fromDate, toDate);
    } else if (type === 'cashbook') {
        generateCashBookStatement(fromDate, toDate);
    } else if (type === 'ledger') {
        generateLedgerStatement(fromDate, toDate);
    }
}
async function generateStatementHeader(title, refNo, fromDate, toDate, subtitle) {
    const branding = await dbGet('settings', 'branding');
    const schoolName = branding ? branding.schoolName : 'College Management System';
    const logo = branding ? branding.logo : null;
    const initials = branding ? branding.initials : 'CM';
    const accentColor = branding ? branding.accentColor : '#f59e0b';
    const tagline = branding ? branding.tagline : '';
    const address = branding ? branding.address : '';
    const phone = branding ? branding.phone : '';
    const email = branding ? branding.email : '';
    let logoHtml;
    if (logo) {
        logoHtml = `<img src="${logo}" style="width:60px;height:60px;object-fit:contain;border-radius:4px;" alt="Logo">`;
    } else {
        logoHtml = `<div style="width:60px;height:60px;background:${accentColor};color:#fff;font-size:22px;font-weight:800;display:flex;align-items:center;justify-content:center;border-radius:4px;">${initials}</div>`;
    }
    let contactHtml = '';
    if (address) contactHtml += `<div>${address}</div>`;
    if (phone) contactHtml += `<div>Tel: ${phone}</div>`;
    if (email) contactHtml += `<div>Email: ${email}</div>`;
    return `
        <div style="border-bottom:3px solid ${accentColor};padding-bottom:14px;margin-bottom:16px;">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;">
                <div style="display:flex;gap:14px;align-items:flex-start;">
                    ${logoHtml}
                    <div>
                        <div style="font-size:18px;font-weight:800;color:#1a1a2e;letter-spacing:0.5px;">${schoolName}</div>
                        ${tagline ? `<div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-top:2px;">${tagline}</div>` : ''}
                        <div style="font-size:9px;color:#94a3b8;margin-top:6px;line-height:1.5;">${contactHtml}</div>
                    </div>
                </div>
                <div style="text-align:right;font-size:10px;color:#64748b;line-height:1.6;">
                    <div style="font-size:11px;font-weight:700;color:#1a1a2e;">${title}</div>
                    <div>Ref: ${refNo}</div>
                    <div>Period: ${formatDate(fromDate)} — ${formatDate(toDate)}</div>
                    <div>Generated: ${new Date().toLocaleString('en-GB', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })}</div>
                </div>
            </div>
        </div>
    `;
}
function generateRefNumber(prefix) {
    return prefix + '-' + new Date().getFullYear() + String(new Date().getMonth() + 1).padStart(2, '0') + '-' + String(Math.floor(Math.random() * 9000) + 1000);
}
async function generateFeeStatement(studentId, fromDate, toDate) {
    try {
        const student = await dbGet('students', studentId);
        if (!student) return showToast('Student not found');
        const allPayments = await dbGetAll('payments');
        const payments = allPayments.filter(p => p.studentId === studentId && p.date >= fromDate && p.date <= toDate).sort((a, b) => a.date.localeCompare(b.date));
        const studentFee = getCachedStudentFee(student);
        const totalPaid = payments.reduce((s, p) => s + p.amount, 0);
        const balance = studentFee - totalPaid;
        const pctPaid = studentFee > 0 ? Math.round((totalPaid / studentFee) * 100) : 0;
        const refNo = generateRefNumber('FEE');
        const branding = await dbGet('settings', 'branding');
        const schoolName = branding ? branding.schoolName : 'College Management System';
        let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
        html += await generateStatementHeader('STUDENT FEE STATEMENT', refNo, fromDate, toDate);
        html += `
            <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:6px;padding:12px;margin-bottom:16px;">
                <div style="font-size:9px;text-transform:uppercase;letter-spacing:1px;color:#64748b;margin-bottom:8px;font-weight:700;">Student Details</div>
                <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;font-size:10px;">
                    <div><span style="color:#94a3b8;">Name</span><br><b>${escapeHtml(student.name)}</b></div>
                    <div><span style="color:#94a3b8;">Admission No.</span><br><b>${escapeHtml(student.admissionNumber || student.id)}</b></div>
                    <div><span style="color:#94a3b8;">Program</span><br><b>${escapeHtml(student.program || '--')}</b></div>
                    <div><span style="color:#94a3b8;">Year / Status</span><br><b>Year ${student.year || 1} — ${escapeHtml(student.status)}</b></div>
                    ${student.email ? `<div><span style="color:#94a3b8;">Email</span><br><span>${escapeHtml(student.email)}</span></div>` : ''}
                    ${student.phone ? `<div><span style="color:#94a3b8;">Phone</span><br><span>${escapeHtml(student.phone)}</span></div>` : ''}
                    ${student.studyCenterId ? `<div><span style="color:#94a3b8;">Study Center</span><br><span>${escapeHtml(student.studyCenterId)}</span></div>` : ''}
                    ${student.enrollDate ? `<div><span style="color:#94a3b8;">Enrollment Date</span><br><span>${formatDate(student.enrollDate)}</span></div>` : ''}
                </div>
            </div>
        `;
        html += `
            <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px;">
                <div style="text-align:center;padding:10px;border:1px solid #e2e8f0;border-radius:6px;"><div style="font-size:9px;text-transform:uppercase;color:#64748b;letter-spacing:0.5px;">Total Fee</div><div style="font-size:16px;font-weight:700;margin-top:4px;">${formatCurrency(studentFee)}</div></div>
                <div style="text-align:center;padding:10px;border:1px solid #059669;border-radius:6px;background:#f0fdf4;"><div style="font-size:9px;text-transform:uppercase;color:#059669;letter-spacing:0.5px;">Total Paid</div><div style="font-size:16px;font-weight:700;color:#059669;margin-top:4px;">${formatCurrency(totalPaid)}</div></div>
                <div style="text-align:center;padding:10px;border:1px solid ${balance > 0 ? '#dc2626' : '#059669'};border-radius:6px;background:${balance > 0 ? '#fef2f2' : '#f0fdf4'};"><div style="font-size:9px;text-transform:uppercase;color:${balance > 0 ? '#dc2626' : '#059669'};letter-spacing:0.5px;">Balance</div><div style="font-size:16px;font-weight:700;color:${balance > 0 ? '#dc2626' : '#059669'};margin-top:4px;">${formatCurrency(balance)}</div></div>
                <div style="text-align:center;padding:10px;border:1px solid #e2e8f0;border-radius:6px;"><div style="font-size:9px;text-transform:uppercase;color:#64748b;letter-spacing:0.5px;">Payment %</div><div style="font-size:16px;font-weight:700;margin-top:4px;">${pctPaid}%</div></div>
            </div>
        `;
        html += `<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#475569;padding-bottom:6px;border-bottom:2px solid #e2e8f0;margin-bottom:8px;">Payment History (${payments.length} transaction${payments.length !== 1 ? 's' : ''})</div>`;
        if (payments.length) {
            html += `<table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;"><thead><tr style="background:#f1f5f9;"><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">#</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Date</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Receipt No.</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Amount</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Method</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Reference</th><th style="padding:6px 8px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Balance</th></tr></thead><tbody>`;
            let runningBal = studentFee;
            payments.forEach((p, idx) => {
                runningBal -= p.amount;
                html += `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 8px;">${idx + 1}</td><td style="padding:6px 8px;">${formatDate(p.date)}</td><td style="padding:6px 8px;font-weight:600;">${escapeHtml(p.receiptNo || '--')}</td><td style="padding:6px 8px;">${formatCurrency(p.amount)}</td><td style="padding:6px 8px;text-transform:capitalize;">${escapeHtml(p.method)}</td><td style="padding:6px 8px;font-size:9px;color:#64748b;">${escapeHtml(p.reference || '--')}</td><td style="padding:6px 8px;text-align:right;font-weight:600;color:${runningBal > 0 ? '#dc2626' : '#059669'};">${formatCurrency(runningBal)}</td></tr>`;
            });
            html += `<tr style="background:#f1f5f9;font-weight:700;"><td colspan="3" style="padding:6px 8px;">TOTAL</td><td style="padding:6px 8px;">${formatCurrency(totalPaid)}</td><td colspan="2" style="padding:6px 8px;"></td><td style="padding:6px 8px;text-align:right;color:${balance > 0 ? '#dc2626' : '#059669'};">${formatCurrency(balance)}</td></tr>`;
            html += `</tbody></table>`;
        } else {
            html += `<div style="text-align:center;padding:20px;color:#64748b;font-size:11px;">No payments recorded in this period.</div>`;
        }
        html += `
            <div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr;gap:40px;font-size:10px;">
                <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
                <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
            </div>
        `;
        html += `<div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">${refNo} — This is a computer-generated statement. ${escapeHtml(schoolName)} Finance Office.</div>`;
        html += `</div>`;
        document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate fee statement: ' + err.message, { type: 'danger' });
        console.error('generateFeeStatement error:', err);
    }
}
async function generateIncomeStatement(fromDate, toDate) {
    try {
        const feePayments = await dbGetAll('payments');
        const otherIncome = await dbGetAll('income');
        const incomeCategories = await dbGetAll('incomeCategories');
        const refNo = generateRefNumber('INC');
        const branding = await dbGet('settings', 'branding');
        const schoolName = branding ? branding.schoolName : 'College Management System';
    const defaultCats = [
        { id: 'INC-DONATION', name: 'Donations & Gifts', icon: '🎁' },
        { id: 'INC-GRANT', name: 'Grants & Sponsorships', icon: '🏛️' },
        { id: 'INC-EVENT', name: 'Events & Conferences', icon: '🎤' },
        { id: 'INC-RENTAL', name: 'Facility Rentals', icon: '🏢' },
        { id: 'INC-INVESTMENT', name: 'Investment Returns', icon: '📈' },
        { id: 'INC-OTHER', name: 'Other Income', icon: '💰' }
    ];
    const allCats = [...defaultCats, ...incomeCategories.filter(c => !defaultCats.find(d => d.id === c.id))];
    const filteredFees = feePayments.filter(p => p.date >= fromDate && p.date <= toDate);
    const filteredIncome = otherIncome.filter(i => i.date >= fromDate && i.date <= toDate);
    const totalFees = filteredFees.reduce((s, p) => s + p.amount, 0);
    const totalOther = filteredIncome.reduce((s, i) => s + i.amount, 0);
    const grandTotal = totalFees + totalOther;
    const methodBreakdown = {};
    filteredFees.forEach(p => { methodBreakdown[p.method] = (methodBreakdown[p.method] || 0) + p.amount; });
    let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
    html += await generateStatementHeader('INCOME STATEMENT', refNo, fromDate, toDate, 'For the Period Ended ' + formatDate(toDate));
    html += `
        <table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;">
            <thead><tr style="background:#f1f5f9;"><th style="padding:8px 10px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;width:50%;">Description</th><th style="padding:8px 10px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Details</th><th style="padding:8px 10px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Amount</th></tr></thead>
            <tbody>
                <tr style="background:#f8fafc;"><td colspan="3" style="padding:8px 10px;font-weight:700;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:1px solid #e2e8f0;">A. Fee Income</td></tr>
                ${Object.entries(methodBreakdown).map(([method, amt]) => {
                    const count = filteredFees.filter(p => p.method === method).length;
                    return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;padding-left:24px;">${method} payments</td><td style="padding:6px 10px;font-size:9px;color:#64748b;">${count} transaction${count !== 1 ? 's' : ''}</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(amt)}</td></tr>`;
                }).join('')}
                <tr style="border-bottom:2px solid #e2e8f0;font-weight:700;"><td style="padding:6px 10px;padding-left:24px;" colspan="2">Total Fee Income</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(totalFees)}</td></tr>
                <tr><td colspan="3" style="padding:8px 10px;font-weight:700;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:1px solid #e2e8f0;background:#f8fafc;">B. Other Income</td></tr>
                ${allCats.map(cat => {
                    const catIncome = filteredIncome.filter(i => i.categoryId === cat.id);
                    const catTotal = catIncome.reduce((s, i) => s + i.amount, 0);
                    if (catTotal === 0 && !catIncome.length) return '';
                    return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;padding-left:24px;">${cat.name}</td><td style="padding:6px 10px;font-size:9px;color:#64748b;">${catIncome.length} record${catIncome.length !== 1 ? 's' : ''}</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(catTotal)}</td></tr>`;
                }).join('')}
                <tr style="border-bottom:2px solid #e2e8f0;font-weight:700;"><td style="padding:6px 10px;padding-left:24px;" colspan="2">Total Other Income</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(totalOther)}</td></tr>
                <tr style="background:#f0fdf4;font-weight:700;border-top:3px double #059669;"><td style="padding:8px 10px;" colspan="2">TOTAL INCOME (A + B)</td><td style="padding:8px 10px;text-align:right;font-size:12px;color:#059669;">${formatCurrency(grandTotal)}</td></tr>
            </tbody>
        </table>
    `;
    if (filteredIncome.length) {
        html += `<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#475569;padding-bottom:6px;border-bottom:2px solid #e2e8f0;margin-bottom:8px;margin-top:16px;">Other Income Details</div>`;
        html += `<table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;"><thead><tr style="background:#f1f5f9;"><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">#</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Date</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Category</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Source</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Description</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Ref.</th><th style="padding:6px 8px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Amount</th></tr></thead><tbody>`;
        filteredIncome.sort((a, b) => a.date.localeCompare(b.date)).forEach((inc, idx) => {
            const cat = allCats.find(c => c.id === inc.categoryId);
            html += `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 8px;">${idx + 1}</td><td style="padding:6px 8px;">${formatDate(inc.date)}</td><td style="padding:6px 8px;">${cat ? cat.name : 'Unknown'}</td><td style="padding:6px 8px;">${inc.source || '--'}</td><td style="padding:6px 8px;font-size:9px;">${inc.description || '--'}</td><td style="padding:6px 8px;font-size:9px;color:#64748b;">${inc.receiptRef || '--'}</td><td style="padding:6px 8px;text-align:right;">${formatCurrency(inc.amount)}</td></tr>`;
        });
        html += `</tbody></table>`;
    }
    html += `
        <div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr;gap:40px;font-size:10px;">
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
        </div>
    `;
    html += `<div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">${refNo} — This is a computer-generated statement. ${escapeHtml(schoolName)} Finance Office.</div>`;
    html += `</div>`;
    document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate income statement: ' + err.message, { type: 'danger' });
        console.error('generateIncomeStatement error:', err);
    }
}
async function generateExpenseStatement(fromDate, toDate) {
    try {
    const expenses = await dbGetAll('expenses');
    const categories = await dbGetAll('expenseCategories');
    const branding = await dbGet('settings', 'branding');
    const schoolName = branding ? branding.schoolName : 'College Management System';
    const refNo = generateRefNumber('EXP');
    const defaultCats = [
        { id: 'CAT-SALARY', name: 'Staff Salaries', icon: '👨‍🏫' },
        { id: 'CAT-UTILITIES', name: 'Utilities', icon: '💡' },
        { id: 'CAT-MAINTENANCE', name: 'Maintenance', icon: '🔧' },
        { id: 'CAT-SUPPLIES', name: 'Supplies', icon: '📦' },
        { id: 'CAT-TRANSPORT', name: 'Transport', icon: '🚌' },
        { id: 'CAT-OTHER', name: 'Other', icon: '📋' }
    ];
    const allCats = [...defaultCats, ...categories.filter(c => !defaultCats.find(d => d.id === c.id))];
    const filtered = expenses.filter(e => e.date >= fromDate && e.date <= toDate);
    const totalExpenses = filtered.reduce((s, e) => s + e.amount, 0);
    let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
    html += await generateStatementHeader('EXPENSE STATEMENT', refNo, fromDate, toDate, 'For the Period Ended ' + formatDate(toDate));
    html += `
        <table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;">
            <thead><tr style="background:#f1f5f9;"><th style="padding:8px 10px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Expense Category</th><th style="padding:8px 10px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Transactions</th><th style="padding:8px 10px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Amount</th><th style="padding:8px 10px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">% of Total</th></tr></thead>
            <tbody>
                ${allCats.map(cat => {
                    const catExpenses = filtered.filter(e => e.categoryId === cat.id);
                    const catTotal = catExpenses.reduce((s, e) => s + e.amount, 0);
                    if (catTotal === 0 && !catExpenses.length) return '';
                    return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;font-weight:600;">${cat.name}</td><td style="padding:6px 10px;text-align:center;">${catExpenses.length}</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(catTotal)}</td><td style="padding:6px 10px;text-align:right;">${totalExpenses > 0 ? Math.round((catTotal / totalExpenses) * 100) : 0}%</td></tr>`;
                }).join('')}
                <tr style="background:#fef2f2;font-weight:700;border-top:3px double #dc2626;"><td style="padding:8px 10px;" colspan="2">TOTAL EXPENSES</td><td style="padding:8px 10px;text-align:right;font-size:12px;color:#dc2626;">${formatCurrency(totalExpenses)}</td><td style="padding:8px 10px;text-align:right;">100%</td></tr>
            </tbody>
        </table>
    `;
    if (filtered.length) {
        html += `<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#475569;padding-bottom:6px;border-bottom:2px solid #e2e8f0;margin-bottom:8px;margin-top:16px;">Expense Details</div>`;
        html += `<table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;"><thead><tr style="background:#f1f5f9;"><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">#</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Date</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Category</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Paid To</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Description</th><th style="padding:6px 8px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Ref.</th><th style="padding:6px 8px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">Amount</th></tr></thead><tbody>`;
        filtered.sort((a, b) => a.date.localeCompare(b.date)).forEach((exp, idx) => {
            const cat = allCats.find(c => c.id === exp.categoryId);
            html += `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 8px;">${idx + 1}</td><td style="padding:6px 8px;">${formatDate(exp.date)}</td><td style="padding:6px 8px;">${cat ? cat.name : 'Unknown'}</td><td style="padding:6px 8px;">${exp.paidTo || '--'}</td><td style="padding:6px 8px;font-size:9px;">${exp.description || '--'}</td><td style="padding:6px 8px;font-size:9px;color:#64748b;">${exp.receiptRef || '--'}</td><td style="padding:6px 8px;text-align:right;">${formatCurrency(exp.amount)}</td></tr>`;
        });
        html += `</tbody></table>`;
    }
    html += `
        <div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr;gap:40px;font-size:10px;">
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
        </div>
    `;
    html += `<div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">${refNo} — This is a computer-generated statement. ${escapeHtml(schoolName)} Finance Office.</div>`;
    html += `</div>`;
    document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate expense statement: ' + err.message, { type: 'danger' });
        console.error('generateExpenseStatement error:', err);
    }
}
async function generateSummaryStatement(fromDate, toDate) {
    try {
    const feePayments = await dbGetAll('payments');
    const otherIncome = await dbGetAll('income');
    const expenses = await dbGetAll('expenses');
    const expCategories = await dbGetAll('expenseCategories');
    const refNo = generateRefNumber('SUM');
    const defaultExpCats = [
        { id: 'CAT-SALARY', name: 'Staff Salaries', icon: '👨‍🏫' },
        { id: 'CAT-UTILITIES', name: 'Utilities', icon: '💡' },
        { id: 'CAT-MAINTENANCE', name: 'Maintenance', icon: '🔧' },
        { id: 'CAT-SUPPLIES', name: 'Supplies', icon: '📦' },
        { id: 'CAT-TRANSPORT', name: 'Transport', icon: '🚌' },
        { id: 'CAT-OTHER', name: 'Other', icon: '📋' }
    ];
    const allExpCats = [...defaultExpCats, ...expCategories.filter(c => !defaultExpCats.find(d => d.id === c.id))];
    const filteredFees = feePayments.filter(p => p.date >= fromDate && p.date <= toDate);
    const filteredIncome = otherIncome.filter(i => i.date >= fromDate && i.date <= toDate);
    const filteredExpenses = expenses.filter(e => e.date >= fromDate && e.date <= toDate);
    const totalFees = filteredFees.reduce((s, p) => s + p.amount, 0);
    const totalOtherIncome = filteredIncome.reduce((s, i) => s + i.amount, 0);
    const totalIncome = totalFees + totalOtherIncome;
    const totalExpenses = filteredExpenses.reduce((s, e) => s + e.amount, 0);
    const netBalance = totalIncome - totalExpenses;
    const surplusDeficit = netBalance >= 0 ? 'SURPLUS' : 'DEFICIT';
    const balanceColor = netBalance >= 0 ? '#059669' : '#dc2626';
    let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
    html += await generateStatementHeader('FINANCIAL SUMMARY', refNo, fromDate, toDate, 'Statement of Income and Expenditure');
    html += `
        <table style="width:100%;border-collapse:collapse;font-size:10px;margin-bottom:16px;">
            <thead><tr style="background:#f1f5f9;"><th style="padding:8px 10px;text-align:left;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;" colspan="2">PARTICULARS</th><th style="padding:8px 10px;text-align:right;border-bottom:2px solid #e2e8f0;font-size:8px;text-transform:uppercase;letter-spacing:0.5px;color:#475569;">AMOUNT</th></tr></thead>
            <tbody>
                <tr style="background:#f8fafc;"><td colspan="3" style="padding:8px 10px;font-weight:700;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:1px solid #e2e8f0;">INCOME</td></tr>
                <tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;padding-left:24px;">Fee Collections</td><td style="padding:6px 10px;font-size:9px;color:#64748b;">${filteredFees.length} transactions</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(totalFees)}</td></tr>
                <tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;padding-left:24px;">Other Income</td><td style="padding:6px 10px;font-size:9px;color:#64748b;">${filteredIncome.length} records</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(totalOtherIncome)}</td></tr>
                <tr style="border-bottom:3px double #059669;font-weight:700;"><td style="padding:6px 10px;padding-left:24px;" colspan="2">TOTAL INCOME</td><td style="padding:6px 10px;text-align:right;color:#059669;">${formatCurrency(totalIncome)}</td></tr>
                <tr><td colspan="3" style="padding:8px 10px;font-weight:700;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:1px solid #e2e8f0;background:#f8fafc;">EXPENDITURE</td></tr>
                ${allExpCats.map(cat => {
                    const catExp = filteredExpenses.filter(e => e.categoryId === cat.id);
                    const catTotal = catExp.reduce((s, e) => s + e.amount, 0);
                    if (catTotal === 0 && !catExp.length) return '';
                    return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:6px 10px;padding-left:24px;">${cat.name}</td><td style="padding:6px 10px;font-size:9px;color:#64748b;">${catExp.length} transaction${catExp.length !== 1 ? 's' : ''}</td><td style="padding:6px 10px;text-align:right;">${formatCurrency(catTotal)}</td></tr>`;
                }).join('')}
                <tr style="border-bottom:3px double #dc2626;font-weight:700;"><td style="padding:6px 10px;padding-left:24px;" colspan="2">TOTAL EXPENDITURE</td><td style="padding:6px 10px;text-align:right;color:#dc2626;">${formatCurrency(totalExpenses)}</td></tr>
                <tr style="background:${netBalance >= 0 ? '#f0fdf4' : '#fef2f2'};font-weight:700;border-top:3px double ${balanceColor};"><td style="padding:10px;" colspan="2">NET ${surplusDeficit} (Income − Expenditure)</td><td style="padding:10px;text-align:right;font-size:14px;color:${balanceColor};">${formatCurrency(Math.abs(netBalance))} ${netBalance >= 0 ? '(Surplus)' : '(Deficit)'}</td></tr>
            </tbody>
        </table>
    `;
    html += `
        <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:6px;padding:12px;margin-bottom:16px;">
            <div style="font-size:9px;text-transform:uppercase;letter-spacing:1px;color:#64748b;margin-bottom:6px;font-weight:700;">Summary</div>
            <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;text-align:center;font-size:11px;">
                <div>Total Income<br><b style="color:#059669;">${formatCurrency(totalIncome)}</b></div>
                <div>Total Expenditure<br><b style="color:#dc2626;">${formatCurrency(totalExpenses)}</b></div>
                <div>Net ${surplusDeficit}<br><b style="color:${balanceColor};font-size:14px;">${formatCurrency(Math.abs(netBalance))}</b></div>
            </div>
        </div>
    `;
    html += `
        <div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:30px;font-size:10px;">
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Accountant / Date</span></div>
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Reviewed By</span><br><span style="font-size:9px;color:#94a3b8;">Finance Manager / Date</span></div>
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Director / Date</span></div>
        </div>
    `;
    const branding = await dbGet('settings', 'branding');
    const schoolName = branding ? branding.schoolName : 'College Management System';
    html += `<div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">${refNo} — This is a computer-generated financial statement. ${escapeHtml(schoolName)} Finance Office.</div>`;
    html += `</div>`;
    document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate summary statement: ' + err.message, { type: 'danger' });
        console.error('generateSummaryStatement error:', err);
    }
}
function printStatement() {
    const content = document.getElementById('statement-print-area');
    if (!content) return showToast('Generate a statement first!');
    const w = window.open('', '', 'width=900,height=700');
    w.document.write(`<html><head><title>Financial Statement</title><style>
        body{margin:0;padding:0;font-family:'Segoe UI',Arial,sans-serif;color:#1a1a2e;background:#fff;font-size:11px;}
        @media print{@page{margin:15mm;size:A4;}}
        @media screen{body{padding:20px;}}
    </style></head><body>${content.innerHTML}</body></html>`);
    w.document.close();
    setTimeout(() => w.print(), 600);
}
function downloadStatementPDF() {
    printStatement();
}
async function loadPayrollStaffSelect() {
    const staff = await dbGetAll('staff');
    const sel = document.getElementById('payroll-staff');
    if (sel) {
        sel.innerHTML = '<option value="">All Staff</option>' + staff.filter(s => s.status === 'active').map(s => `<option value="${s.id}">${escapeHtml(s.name)}</option>`).join('');
    }
    const m = document.getElementById('payroll-month');
    if (m) m.value = new Date().toISOString().slice(0, 7);
    renderDeductionsSummary();
    renderDeductionAccounts();
}
async function renderDeductionAccounts() {
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const accounts = await dbGetAll('deductionAccounts').catch(() => []);
    const container = document.getElementById('deduction-accounts-list');
    if (!container) return;
    if (!deductions.length) {
        container.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-muted);">Add deductions first before setting destinations.</div>';
        return;
    }
    const linkedAccounts = accounts.filter(a => deductions.some(d => d.id === a.deductionId));
    const unlinkedDeductions = deductions.filter(d => !accounts.some(a => a.deductionId === d.id));
    let html = '<table class="data-table" style="font-size:11px;background:#1e293b;color:#fff;"><thead><tr style="background:#334155;"><th>Deduction</th><th>Institution</th><th>Account No.</th><th>Bank</th><th>Actions</th></tr></thead><tbody>';
    linkedAccounts.forEach(acc => {
        const ded = deductions.find(d => d.id === acc.deductionId);
        html += `<tr style="border-bottom:1px solid #475569;">
            <td style="padding:8px;">${escapeHtml(ded?.name || 'Unknown')}</td>
            <td style="padding:8px;">${escapeHtml(acc.institutionName)}</td>
            <td style="padding:8px;">${escapeHtml(acc.accountNumber)}</td>
            <td style="padding:8px;">${escapeHtml(acc.bankName || '-')}</td>
            <td style="padding:8px;">
                <button class="btn btn-outline btn-sm" onclick="showDeductionAccountForm('${acc.id}')" style="background:#334155;color:#fff;border-color:#475569;">Edit</button>
                <button class="btn btn-outline btn-sm" onclick="deleteDeductionAccount('${acc.id}')" style="background:#dc2626;color:#fff;border-color:#dc2626;">X</button>
            </td>
        </tr>`;
    });
    if (!linkedAccounts.length) {
        html += '<tr><td colspan="5" style="text-align:center;padding:20px;color:#94a3b8;">No accounts configured. Click "Add Account" to set up deduction destinations.</td></tr>';
    }
    html += '</tbody></table>';
    if (unlinkedDeductions.length) {
        html += `<div style="margin-top:12px;padding:8px;background:#854d0e;color:#fff;border-radius:4px;font-size:11px;">
            <b>Unlinked Deductions:</b> ${unlinkedDeductions.map(d => d.name).join(', ')}
        </div>`;
    }
    container.innerHTML = html;
}
async function showDeductionAccountForm(existingId = null) {
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const accounts = await dbGetAll('deductionAccounts').catch(() => []);
    const existing = existingId ? accounts.find(a => a.id === existingId) : null;
    const dedOptions = deductions.map(d => `<option value="${d.id}" ${existing?.deductionId === d.id ? 'selected' : ''}>${escapeHtml(d.name)} ${d.isPercentage ? '(' + d.value + '%)' : ''}</option>`).join('');
    const content = `
        <div class="form-row">
            <div class="form-group"><label>Deduction Type *</label><select id="da-deduction">${dedOptions}</select></div>
        </div>
        <div class="form-row">
            <div class="form-group"><label>Institution Name *</label><input type="text" id="da-institution" value="${existing ? escapeHtml(existing.institutionName) : ''}" placeholder="e.g., KRA, SHA, Welfare Fund"></div>
        </div>
        <div class="form-row">
            <div class="form-group"><label>Account Number *</label><input type="text" id="da-account" value="${existing ? escapeHtml(existing.accountNumber) : ''}" placeholder="Account/Reference Number"></div>
            <div class="form-group"><label>Bank Name</label><input type="text" id="da-bank" value="${existing ? escapeHtml(existing.bankName || '') : ''}" placeholder="e.g., KCB, Equity, Co-op"></div>
        </div>
        <div class="form-group"><label>Notes</label><input type="text" id="da-notes" value="${existing ? escapeHtml(existing.notes || '') : ''}" placeholder="Any additional instructions"></div>
    `;
    showModal(existing ? 'Edit Deduction Account' : 'Add Deduction Account', content, 
        `<button class="btn btn-primary" onclick="saveDeductionAccount('${existingId || ''}')">Save</button>${existingId ? `<button class="btn btn-danger" onclick="deleteDeductionAccount('${existingId}')" style="margin-left:8px;">Delete</button>` : ''}`);
}
async function saveDeductionAccount(id) {
    const deductionId = document.getElementById('da-deduction').value;
    const institutionName = document.getElementById('da-institution').value.trim();
    const accountNumber = document.getElementById('da-account').value.trim();
    const bankName = document.getElementById('da-bank').value.trim();
    const notes = document.getElementById('da-notes').value.trim();
    if (!institutionName || !accountNumber) return showToast('Enter institution name and account number!', { type: 'danger' });
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const ded = deductions.find(d => d.id === deductionId);
    const account = {
        id: id || 'DA-' + Date.now(),
        deductionId,
        deductionName: ded?.name || '',
        institutionName,
        accountNumber,
        bankName,
        notes,
        updatedAt: new Date().toISOString()
    };
    await dbPut('deductionAccounts', account);
    closeModal();
    renderDeductionAccounts();
    showToast('Deduction account saved');
}
async function deleteDeductionAccount(id) {
    if (!await showConfirm('Delete Account', 'Remove this deduction destination?')) return;
    await dbDelete('deductionAccounts', id);
    closeModal();
    renderDeductionAccounts();
    showToast('Account deleted');
}
async function generateDisbursementReport() {
    const month = document.getElementById('payroll-month')?.value;
    if (!month) return showToast('Select a month first!');
    const payslips = await dbGetAll('payslips').catch(() => []);
    const paidSlips = payslips.filter(p => p.month === month && p.paid);
    if (!paidSlips.length) return showToast('No paid slips for this month!');
    const accounts = await dbGetAll('deductionAccounts').catch(() => []);
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const disbursements = {};
    paidSlips.forEach(p => {
        if (p.deductions) {
            p.deductions.forEach(d => {
                const acc = accounts.find(a => a.deductionId === d.deductionId || a.deductionName === d.name);
                if (acc) {
                    if (!disbursements[acc.id]) {
                        disbursements[acc.id] = {
                            institution: acc.institutionName,
                            account: acc.accountNumber,
                            bank: acc.bankName || '',
                            deductionName: d.name,
                            total: 0,
                            staff: []
                        };
                    }
                    disbursements[acc.id].total += d.amount;
                    disbursements[acc.id].staff.push({ name: p.staffName, amount: d.amount });
                }
            });
        }
    });
    let html = `<div style="padding:20px;font-family:Arial,sans-serif;max-width:800px;">
        <div style="text-align:center;border-bottom:2px solid #000;padding-bottom:10px;margin-bottom:20px;">
            <div style="font-size:16px;font-weight:bold;">DISBURSEMENT REPORT</div>
            <div style="font-size:12px;color:#666;">Period: ${month}</div>
            <div style="font-size:11px;color:#666;">Generated: ${new Date().toLocaleString()}</div>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:11px;">
            <thead style="background:#f1f5f9;">
                <tr>
                    <th style="padding:8px;border:1px solid #ccc;text-align:left;">Institution</th>
                    <th style="padding:8px;border:1px solid #ccc;text-align:left;">Account No.</th>
                    <th style="padding:8px;border:1px solid #ccc;text-align:left;">Bank</th>
                    <th style="padding:8px;border:1px solid #ccc;text-align:left;">Deduction</th>
                    <th style="padding:8px;border:1px solid #ccc;text-align:right;">Total Amount</th>
                    <th style="padding:8px;border:1px solid #ccc;text-align:left;">Staff Count</th>
                </tr>
            </thead>
            <tbody>`;
    let grandTotal = 0;
    Object.values(disbursements).forEach(d => {
        grandTotal += d.total;
        html += `<tr>
            <td style="padding:8px;border:1px solid #ccc;font-weight:600;">${escapeHtml(d.institution)}</td>
            <td style="padding:8px;border:1px solid #ccc;">${escapeHtml(d.account)}</td>
            <td style="padding:8px;border:1px solid #ccc;">${escapeHtml(d.bank)}</td>
            <td style="padding:8px;border:1px solid #ccc;">${escapeHtml(d.deductionName)}</td>
            <td style="padding:8px;border:1px solid #ccc;text-align:right;font-weight:600;">${formatCurrency(d.total)}</td>
            <td style="padding:8px;border:1px solid #ccc;">${d.staff.length} staff</td>
        </tr>`;
    });
    html += `</tbody>
        <tfoot style="background:#1e293b;color:#fff;">
            <tr>
                <td colspan="4" style="padding:10px;border:1px solid #1e293b;font-weight:bold;">GRAND TOTAL</td>
                <td style="padding:10px;border:1px solid #1e293b;text-align:right;font-weight:bold;font-size:14px;">${formatCurrency(grandTotal)}</td>
                <td style="padding:10px;border:1px solid #1e293b;">${paidSlips.length} payslips</td>
            </tr>
        </tfoot>
        </table>
        <div style="margin-top:20px;font-size:11px;">
            <b>Staff Breakdown:</b>
            ${paidSlips.map(p => `<div style="margin:4px 0;padding:4px;background:#f8fafc;border-radius:4px;">${escapeHtml(p.staffName)}: ${formatCurrency(p.totalDeductions)} deduction</div>`).join('')}
        </div>
        <div style="margin-top:20px;display:grid;grid-template-columns:1fr 1fr;gap:30px;font-size:10px;">
            <div style="border-top:1px solid #000;padding-top:6px;">Prepared By / Date</div>
            <div style="border-top:1px solid #000;padding-top:6px;">Approved By / Date</div>
        </div>
    </div>`;
    showModal('Disbursement Report - ' + month, `
        <div style="margin-bottom:12px;display:flex;gap:8px;">
            <button class="btn btn-primary" onclick="printDisbursementReport()">Print Report</button>
        </div>
        <div style="border:1px solid #ccc;padding:10px;max-height:500px;overflow:auto;background:#fff;">${html}</div>
    `, `<button class="btn btn-secondary" onclick="closeModal()">Close</button>`);
}
function printDisbursementReport() {
    const content = document.querySelector('#modal-content div:last-child');
    if (!content) return;
    const w = window.open('', '', 'width=900,height=700');
    w.document.write(`<html><head><title>Disbursement Report</title><style>body{padding:20px;font-family:Arial,sans-serif;}@media print{@page{size:A4;margin:15mm;}}</style></head><body>${content.innerHTML}</body></html>`);
    w.document.close();
    setTimeout(() => w.print(), 500);
}
async function renderDeductionsSummary() {
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const container = document.getElementById('deductions-summary');
    if (!container) return;
    if (!deductions.length) {
        container.innerHTML = '<span style="color:var(--text-muted);font-size:12px;">No deductions configured. Click "Deductions" to add.</span>';
    } else {
        container.innerHTML = deductions.map(d => `<div style="font-size:12px;padding:6px 10px;background:#1e293b;color:#fff;border-radius:4px;font-weight:500;"><b>${escapeHtml(d.name)}</b>: ${d.isPercentage ? d.value + '%' : formatCurrency(d.value)} ${d.isTax ? ' (Tax)' : ''}</div>`).join('');
    }
}
async function showDeductionForm(existingId = null) {
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const existing = existingId ? deductions.find(d => d.id === existingId) : null;
    const content = `
        <div class="form-group"><label>Deduction Name *</label><input type="text" id="deduction-name" value="${existing ? escapeHtml(existing.name) : ''}" placeholder="e.g., Tax, NHF, Pension, Insurance"></div>
        <div class="form-row">
            <div class="form-group"><label>Value *</label><input type="number" id="deduction-value" value="${existing ? existing.value : ''}" placeholder="0.00"></div>
            <div class="form-group"><label>Type</label><select id="deduction-type"><option value="fixed" ${existing && !existing.isPercentage ? 'selected' : ''}>Fixed Amount</option><option value="percentage" ${existing && existing.isPercentage ? 'selected' : ''}>Percentage (%)</option></select></div>
        </div>
        <div class="form-group"><label><input type="checkbox" id="deduction-tax" ${existing && existing.isTax ? 'checked' : ''}> Is Tax Deduction?</label></div>
        <div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap;">
            ${deductions.map(d => `<button class="btn btn-outline btn-sm" onclick="showDeductionForm('${d.id}')" style="margin:2px;">${escapeHtml(d.name)}</button>`).join('')}
        </div>
    `;
    const title = existing ? 'Edit Deduction' : 'Add Deduction';
    showModal(title, content, `<button class="btn btn-primary" onclick="saveDeduction('${existingId || ''}')">Save Deduction</button>${existingId ? `<button class="btn btn-danger" onclick="deleteDeduction('${existingId}')" style="margin-left:8px;">Delete</button>` : ''}`);
}
async function saveDeduction(id) {
    const name = document.getElementById('deduction-name').value.trim();
    const value = parseFloat(document.getElementById('deduction-value').value) || 0;
    const isPercentage = document.getElementById('deduction-type').value === 'percentage';
    const isTax = document.getElementById('deduction-tax')?.checked || false;
    if (!name) return showToast('Enter deduction name!');
    const deduction = { id: id || 'DED-' + Date.now(), name, value, isPercentage, isTax };
    await dbPut('salaryDeductions', deduction);
    closeModal();
    renderDeductionsSummary();
    showToast('Deduction saved');
}
async function deleteDeduction(id) {
    if (!await showConfirm('Delete Deduction', 'Delete this deduction?')) return;
    await dbDelete('salaryDeductions', id);
    closeModal();
    renderDeductionsSummary();
    showToast('Deduction deleted');
}
async function showPayrollRunForm() {
    const staff = await dbGetAll('staff').then(s => s.filter(s => s.status === 'active'));
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    const month = document.getElementById('payroll-month')?.value || new Date().toISOString().slice(0, 7);
    const staffOptions = staff.map(s => {
        const salary = s.basicSalary || 0;
        return `<option value="${s.id}" data-salary="${salary}">${escapeHtml(s.name)} - Base: ${formatCurrency(salary)}</option>`;
    }).join('');
    const content = `
        <div class="form-group"><label>Staff Member *</label><select id="payrun-staff" onchange="updatePayrunPreview()">${staffOptions}</select></div>
        <div class="form-row">
            <div class="form-group"><label>Basic Salary</label><input type="number" id="payrun-basic" value="${staff[0]?.basicSalary || 0}" onchange="updatePayrunPreview()"></div>
            <div class="form-group"><label>Allowances</label><input type="number" id="payrun-allowances" value="0" onchange="updatePayrunPreview()"></div>
        </div>
        <div class="form-group"><label>Month</label><input type="month" id="payrun-month" value="${month}"></div>
        <div id="payrun-preview" style="margin:12px 0;padding:12px;background:var(--bg-input);border-radius:var(--radius);font-size:13px;"></div>
    `;
    showModal('Run Payroll', content, `<button class="btn btn-primary" onclick="runPayroll()">Generate Payslip</button>`);
    updatePayrunPreview();
}
async function updatePayrunPreview() {
    const basic = parseFloat(document.getElementById('payrun-basic')?.value) || 0;
    const allowances = parseFloat(document.getElementById('payrun-allowances')?.value) || 0;
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    let gross = basic + allowances;
    let totalDeductions = 0;
    let dedHtml = '<b>Deductions:</b><br>';
    for (const d of deductions) {
        const amount = d.isPercentage ? (gross * d.value / 100) : d.value;
        totalDeductions += amount;
        dedHtml += `${d.name}: ${formatCurrency(amount)}<br>`;
    }
    const net = gross - totalDeductions;
    document.getElementById('payrun-preview').innerHTML = `
        <b>Gross:</b> ${formatCurrency(gross)}<br>
        ${dedHtml}
        <b>Total Deductions:</b> ${formatCurrency(totalDeductions)}<br>
        <b style="color:var(--success);font-size:16px;">NET PAY: ${formatCurrency(net)}</b>
    `;
}
async function runPayroll() {
    const staffId = document.getElementById('payrun-staff').value;
    const basic = parseFloat(document.getElementById('payrun-basic').value) || 0;
    const allowances = parseFloat(document.getElementById('payrun-allowances').value) || 0;
    const month = document.getElementById('payrun-month').value;
    if (!staffId || !month) return showToast('Select staff and month!');
    const staff = await dbGet('staff', staffId);
    const deductions = await dbGetAll('salaryDeductions').catch(() => []);
    let gross = basic + allowances;
    let payslipDeductions = [];
    let totalDeductions = 0;
    for (const d of deductions) {
        const amount = d.isPercentage ? (gross * d.value / 100) : d.value;
        totalDeductions += amount;
        payslipDeductions.push({ deductionId: d.id, name: d.name, amount, isTax: d.isTax });
    }
    const net = gross - totalDeductions;
    const payslip = {
        id: 'PSL-' + Date.now(),
        staffId,
        staffName: staff?.name || '',
        staffRole: staff?.role || '',
        month,
        basicSalary: basic,
        allowances,
        grossSalary: gross,
        deductions: payslipDeductions,
        totalDeductions,
        netSalary: net,
        paid: false,
        paidAt: null,
        createdAt: new Date().toISOString()
    };
    await dbPut('payslips', payslip);
    closeModal();
    renderPayrollList();
    showToast('Payslip generated');
}
async function renderPayrollList() {
    const month = document.getElementById('payroll-month')?.value;
    const staffFilter = document.getElementById('payroll-staff')?.value;
    let payslips = await dbGetAll('payslips').catch(() => []);
    if (month) payslips = payslips.filter(p => p.month === month);
    if (staffFilter) payslips = payslips.filter(p => p.staffId === staffFilter);
    payslips.sort((a, b) => a.staffName.localeCompare(b.staffName));
    const container = document.getElementById('payroll-list');
    if (!container) return;
    if (!payslips.length) {
        container.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted);">No payslips found for selected period.</div>';
        return;
    }
    container.innerHTML = `<table class="data-table"><thead><tr><th>Staff</th><th>Month</th><th>Gross</th><th>Deductions</th><th>Net</th><th>Status</th><th>Actions</th></tr></thead><tbody>` +
        payslips.map(p => `
            <tr>
                <td>${escapeHtml(p.staffName)}<br><small>${escapeHtml(p.staffRole || '')}</small></td>
                <td>${p.month}</td>
                <td>${formatCurrency(p.grossSalary)}</td>
                <td>${formatCurrency(p.totalDeductions)}</td>
                <td style="font-weight:700;color:var(--success);">${formatCurrency(p.netSalary)}</td>
                <td>${p.paid ? '<span style="color:var(--success);">Paid</span>' : '<span style="color:var(--warning);">Pending</span>'}</td>
                <td>
                    <button class="btn btn-outline btn-sm" onclick="printPayslip('${p.id}')" title="Print">🖨️</button>
                    <button class="btn btn-outline btn-sm" onclick="editPayslip('${p.id}')" title="Edit">✏️</button>
                    <button class="btn btn-outline btn-sm" onclick="deletePayslip('${p.id}')" title="Delete" style="color:var(--danger);">X</button>
                </td>
            </tr>
        `).join('') + '</tbody></table>';
}
async function editPayslip(payslipId) {
    const payslips = await dbGetAll('payslips').catch(() => []);
    const p = payslips.find(ps => ps.id === payslipId);
    if (!p) return showToast('Payslip not found!');
    const staff = await dbGetAll('staff').then(s => s.filter(s => s.status === 'active'));
    const staffOptions = staff.map(s => `<option value="${s.id}" ${p.staffId === s.id ? 'selected' : ''}>${escapeHtml(s.name)}</option>`).join('');
    const content = `
        <div class="form-group"><label>Staff Member *</label><select id="edit-payrun-staff">${staffOptions}</select></div>
        <div class="form-row">
            <div class="form-group"><label>Basic Salary</label><input type="number" id="edit-payrun-basic" value="${p.basicSalary}"></div>
            <div class="form-group"><label>Allowances</label><input type="number" id="edit-payrun-allowances" value="${p.allowances}"></div>
        </div>
        <div class="form-group"><label>Month</label><input type="month" id="edit-payrun-month" value="${p.month}"></div>
    `;
    showModal('Edit Payslip', content, `<button class="btn btn-primary" onclick="saveEditedPayslip('${p.id}')">Save Changes</button>`);
}
