async function printPayslip(payslipId) {
    const payslips = await dbGetAll('payslips').catch(() => []);
    const p = payslips.find(ps => ps.id === payslipId);
    if (!p) return showToast('Payslip not found!');
    const branding = await dbGet('settings', 'branding').catch(() => null);
    const schoolName = branding?.schoolName || 'NET FOUNDATION KENYA';
    const esc = (s) => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    const content = `
        <div style="background:#1e293b;color:#fff;padding:15px;border-radius:8px;">
        <div style="text-align:center;font-weight:bold;font-size:16px;margin-bottom:8px;color:#fff;">${esc(schoolName)}</div>
        <div style="text-align:center;border-bottom:1px solid #475569;padding-bottom:8px;margin-bottom:8px;color:#94a3b8;">PAYSLIP</div>
        <div style="font-size:12px;margin:4px 0;"><span style="color:#94a3b8;">Staff:</span> ${esc(p.staffName)}</div>
        <div style="font-size:12px;margin:4px 0;"><span style="color:#94a3b8;">Role:</span> ${esc(p.staffRole || 'Staff')}</div>
        <div style="font-size:12px;margin:4px 0;"><span style="color:#94a3b8;">Period:</span> ${esc(p.month)}</div>
        <div style="border-top:1px solid #475569;border-bottom:1px solid #475569;padding:8px 0;margin:8px 0;">
            <div style="display:flex;justify-content:space-between;font-size:11px;margin:2px 0;"><span style="color:#94a3b8;">Basic Salary:</span><span>${formatCurrency(p.basicSalary)}</span></div>
            <div style="display:flex;justify-content:space-between;font-size:11px;margin:2px 0;"><span style="color:#94a3b8;">Allowances:</span><span>${formatCurrency(p.allowances)}</span></div>
            <div style="display:flex;justify-content:space-between;font-size:12px;font-weight:bold;margin-top:4px;"><span style="color:#86efac;">GROSS:</span><span style="color:#86efac;">${formatCurrency(p.grossSalary)}</span></div>
        </div>
        <div style="font-size:11px;margin:8px 0;color:#94a3b8;">Deductions:</div>
        ${p.deductions.map(d => `<div style="display:flex;justify-content:space-between;font-size:10px;margin:2px 0;"><span style="color:#94a3b8;">${esc(d.name)}:</span><span style="color:#fca5a5;">-${formatCurrency(d.amount)}</span></div>`).join('')}
        <div style="display:flex;justify-content:space-between;font-size:11px;margin-top:4px;border-top:1px solid #475569;padding-top:4px;"><span style="color:#94a3b8;">Total Ded:</span><span style="color:#fca5a5;">${formatCurrency(p.totalDeductions)}</span></div>
        <div style="display:flex;justify-content:space-between;font-size:16px;font-weight:bold;margin:12px 0;border-top:2px solid #fff;padding-top:8px;"><span style="color:#fff;">NET PAY:</span><span style="color:#86efac;">${formatCurrency(p.netSalary)}</span></div>
        <div style="text-align:center;font-size:11px;padding:8px;background:${p.paid ? '#166534' : '#854d0e'};border-radius:4px;margin:8px 0;color:#fff;font-weight:bold;">
            ${p.paid ? 'PAID' : 'PENDING'} ${p.paidAt ? '- ' + new Date(p.paidAt).toLocaleDateString() : ''}
        </div>
        <div style="text-align:center;font-size:9px;color:#64748b;margin-top:8px;border-top:1px solid #475569;padding-top:8px;">${esc(schoolName)}</div>
        </div>
    `;
    showModal('Print Payslip', `
        <div style="display:flex;gap:8px;margin-bottom:12px;">
            <button class="btn btn-primary" onclick="doPrintPayslip('${p.id}', '58mm')">&#x1F4A8; 58mm Thermal</button>
            <button class="btn btn-outline" onclick="doPrintPayslip('${p.id}', 'a6')">&#x1F4C4; A6 Paper</button>
        </div>
        <div style="border:1px solid #ccc;padding:10px;max-height:400px;overflow:auto;">${content}</div>
    `, `<button class="btn btn-secondary" onclick="closeModal()">Close</button>`);
}
async function doPrintPayslip(payslipId, size) {
    const payslips = await dbGetAll('payslips').catch(() => []);
    const p = payslips.find(ps => ps.id === payslipId);
    if (!p) return showToast('Payslip not found!');
    const branding = await dbGet('settings', 'branding').catch(() => null);
    const schoolName = branding?.schoolName || 'NET FOUNDATION KENYA';
    const line = (t) => t + '\n';
    const sep = '='.repeat(32) + '\n';
    const dash = '-'.repeat(32) + '\n';
    const center = (t) => t.padStart((32 + t.length) / 2).padEnd(32) + '\n';
    const row = (l, r) => l.padEnd(16) + r.padStart(16) + '\n';
    let receipt = '';
    receipt += sep;
    receipt += center(schoolName.length > 20 ? schoolName.substring(0, 20) : schoolName);
    receipt += sep;
    receipt += center('PAYSLIP');
    receipt += dash;
    receipt += row('Staff:', p.staffName.substring(0, 22));
    receipt += row('Role:', p.staffRole ? p.staffRole.substring(0, 16) : 'Staff');
    receipt += row('Period:', p.month);
    receipt += dash;
    receipt += row('Basic Salary:', formatCurrency(p.basicSalary));
    receipt += row('Allowances:', formatCurrency(p.allowances));
    receipt += sep;
    receipt += row('GROSS:', formatCurrency(p.grossSalary));
    receipt += dash;
    receipt += line('Deductions:');
    if (p.deductions && p.deductions.length > 0) {
        p.deductions.forEach(d => {
            receipt += row('  ' + d.name.substring(0, 12), '-' + formatCurrency(d.amount));
        });
    } else {
        receipt += row('  None', '0.00');
    }
    receipt += sep;
    receipt += row('Total Ded:', formatCurrency(p.totalDeductions));
    receipt += sep;
    receipt += center('*** NET PAY ***');
    receipt += center(formatCurrency(p.netSalary));
    receipt += sep;
    receipt += center(p.paid ? 'PAID' : 'PENDING');
    if (p.paidAt) receipt += center(new Date(p.paidAt).toLocaleDateString());
    receipt += sep;
    receipt += center(schoolName.substring(0, 24));
    if (typeof btPrinterCharacteristic !== 'undefined' && btPrinterCharacteristic) {
        try {
            const receiptLogo = branding?.receiptLogo || branding?.logo;
            let logoBitmap = null;
            if (receiptLogo && typeof imageUrlToEscPosBitmap === 'function') {
                try {
                    logoBitmap = await imageUrlToEscPosBitmap(receiptLogo, 320);
                } catch (_) {}
            }
            const escPos = typeof buildEscPosData === 'function' 
                ? buildEscPosData(receipt, logoBitmap, schoolName) 
                : new TextEncoder().encode(receipt);
            let ok = false;
            try {
                await writeBytesToPrinter(escPos);
                ok = true;
            } catch (_) {
                if (typeof sendToBluetoothPrinterRaw === 'function') {
                    ok = await sendToBluetoothPrinterRaw(escPos);
                }
            }
            if (ok) {
                showToast('Payslip sent to Bluetooth printer!', { type: 'success' });
            }
            return;
        } catch (err) {
            console.error('Bluetooth print error:', err);
        }
    }
    const w = window.open('', '_blank', 'width=350,height=600');
    w.document.write(`<!DOCTYPE html><html><head><title>Payslip - ${p.staffName}</title>
<style>
@page { size: 58mm 200mm; margin: 0; }
body { font-family: 'Courier New', monospace; font-size: 9px; line-height: 1.2; margin: 0; padding: 5px; width: 48mm; }
@media print { body { margin: 0; padding: 0; } }
</style></head><body>
<pre style="margin:0;font-family:'Courier New',monospace;font-size:8px;line-height:1.1;">${receipt}</pre>
<script>window.onload=function(){setTimeout(function(){window.print()},500);}<\/script>
</body></html>`);
    w.document.close();
}
async function payStaff(payslipId) {
    if (!await showConfirm('Pay Staff', 'Mark as paid and record expense?')) return;
    const payslips = await dbGetAll('payslips').catch(() => []);
    const p = payslips.find(ps => ps.id === payslipId);
    if (!p) return showToast('Payslip not found!');
    p.paid = true;
    p.paidAt = new Date().toISOString();
    await dbPut('payslips', p);
    const expense = {
        id: 'EXP-PAY-' + Date.now(),
        date: p.paidAt.split('T')[0],
        categoryId: 'CAT-SALARY',
        amount: p.netSalary,
        description: `Salary - ${p.staffName} - ${p.month}`,
        paidTo: p.staffName,
        receiptRef: p.id,
        createdAt: new Date().toISOString()
    };
    await dbPut('expenses', expense);
    const accounts = await dbGetAll('deductionAccounts').catch(() => []);
    if (p.deductions && accounts.length) {
        const disbursement = {
            id: 'DIS-' + Date.now(),
            payslipId: p.id,
            staffName: p.staffName,
            month: p.month,
            paidAt: p.paidAt,
            deductions: p.deductions.map(d => {
                const acc = accounts.find(a => a.deductionId === d.deductionId || a.deductionName === d.name);
                return {
                    deductionName: d.name,
                    amount: d.amount,
                    institutionName: acc?.institutionName || '',
                    accountNumber: acc?.accountNumber || '',
                    bankName: acc?.bankName || '',
                    disbursed: false
                };
            }),
            totalDeductions: p.totalDeductions,
            status: 'pending'
        };
        await dbPut('deductionDisbursements', disbursement);
    }
    renderPayrollList();
    renderPayroll();
    showToast('Staff paid and expense recorded');
}
async function getTrueBalance(asOfDate) {
    const payments = await dbGetAll('payments').catch(() => []);
    const income = await dbGetAll('income').catch(() => []);
    const expenses = await dbGetAll('expenses').catch(() => []);
    const beforePayments = payments.filter(p => p.date < asOfDate).reduce((s, p) => s + p.amount, 0);
    const beforeIncome = income.filter(i => i.date < asOfDate).reduce((s, i) => s + i.amount, 0);
    const beforeExpenses = expenses.filter(e => e.date < asOfDate).reduce((s, e) => s + e.amount, 0);
    return (beforePayments + beforeIncome) - beforeExpenses;
}
async function generateCashBookStatement(fromDate, toDate) {
    try {
        console.log('Generating Cash Book from', fromDate, 'to', toDate);
        const payments = await dbGetAll('payments').catch(() => []);
        const income = await dbGetAll('income').catch(() => []);
        const expenses = await dbGetAll('expenses').catch(() => []);
        const students = await dbGetAll('students').catch(() => []);
        const periodPayments = payments.filter(p => p.date >= fromDate && p.date <= toDate);
        const periodIncome = income.filter(i => i.date >= fromDate && i.date <= toDate);
        const periodExpenses = expenses.filter(e => e.date >= fromDate && e.date <= toDate);
        const totalFeeIncome = periodPayments.reduce((s, p) => s + p.amount, 0);
        const totalOtherIncome = periodIncome.reduce((s, i) => s + i.amount, 0);
        const totalIncome = totalFeeIncome + totalOtherIncome;
        const totalExpenses = periodExpenses.reduce((s, e) => s + e.amount, 0);
        const openingBalance = await getTrueBalance(fromDate);
        const closingBalance = openingBalance + totalIncome - totalExpenses;
        const allTxns = [];
        periodPayments.forEach(p => {
            const s = students.find(st => st.id === p.studentId);
            allTxns.push({ date: p.date, type: 'receipt', description: `Fee Payment - ${s ? s.name : p.studentId}`, ref: p.receiptNo || p.id, amount: p.amount, isIncome: true });
        });
        periodIncome.forEach(i => {
            allTxns.push({ date: i.date, type: 'income', description: i.description || i.source || 'Other Income', ref: i.receiptRef || i.id, amount: i.amount, isIncome: true });
        });
        periodExpenses.forEach(e => {
            allTxns.push({ date: e.date, type: 'expense', description: e.description || e.paidTo || 'Expense', ref: e.receiptRef || e.id, amount: e.amount, isIncome: false });
        });
        allTxns.sort((a, b) => a.date.localeCompare(b.date));
        let runningBal = openingBalance;
        const txnRows = allTxns.map((t, i) => {
            runningBal += t.isIncome ? t.amount : -t.amount;
            const rowClass = i % 2 === 1 ? 'background:#f8fafc;' : '';
            return `<tr style="${rowClass}">
                <td style="padding:6px 8px;border:1px solid #e2e8f0;font-size:10px;">${formatDate(t.date)}</td>
                <td style="padding:6px 8px;border:1px solid #e2e8f0;font-size:10px;">${escapeHtml(t.description.substring(0,35))}</td>
                <td style="padding:6px 8px;border:1px solid #e2e8f0;font-size:9px;color:#64748b;">${escapeHtml(t.ref.substring(0,15))}</td>
                <td style="padding:6px 8px;border:1px solid #e2e8f0;text-align:right;color:var(--success);font-size:10px;">${t.isIncome ? formatCurrency(t.amount) : ''}</td>
                <td style="padding:6px 8px;border:1px solid #e2e8f0;text-align:right;color:var(--danger);font-size:10px;">${!t.isIncome ? formatCurrency(t.amount) : ''}</td>
                <td style="padding:6px 8px;border:1px solid #e2e8f0;text-align:right;font-weight:600;font-size:10px;${runningBal < 0 ? 'color:var(--danger);' : ''}">${formatCurrency(runningBal)}</td>
            </tr>`;
        }).join('');
        const cashRefNo = generateRefNumber('CB');
        const branding = await dbGet('settings', 'branding').catch(() => null);
        const schoolName = branding?.schoolName || 'NET FOUNDATION KENYA';
        let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
        html += await generateStatementHeader('CASH BOOK', cashRefNo, fromDate, toDate);
        html += `<table style="width:100%;border-collapse:collapse;margin-bottom:16px;font-size:11px;">
                <tr style="background:#f1f5f9;"><td style="padding:10px;font-weight:700;border:1px solid #e2e8f0;">BALANCE BROUGHT FORWARD</td><td style="padding:10px;text-align:right;font-weight:700;border:1px solid #e2e8f0;${openingBalance < 0 ? 'color:var(--danger);' : 'color:var(--success);'}">${formatCurrency(openingBalance)}</td></tr>
                <tr><td style="padding:10px;font-weight:600;border:1px solid #e2e8f0;color:var(--success);">+ Fee Income</td><td style="padding:10px;text-align:right;font-weight:600;border:1px solid #e2e8f0;color:var(--success);">${formatCurrency(totalFeeIncome)}</td></tr>
                <tr><td style="padding:10px;font-weight:600;border:1px solid #e2e8f0;color:var(--info);">+ Other Income</td><td style="padding:10px;text-align:right;font-weight:600;border:1px solid #e2e8f0;color:var(--info);">${formatCurrency(totalOtherIncome)}</td></tr>
                <tr><td style="padding:10px;font-weight:600;border:1px solid #e2e8f0;color:var(--danger);">- Total Expenses</td><td style="padding:10px;text-align:right;font-weight:600;border:1px solid #e2e8f0;color:var(--danger);">(${formatCurrency(totalExpenses)})</td></tr>
                <tr style="background:#1e293b;color:#fff;"><td style="padding:12px;font-weight:700;border:1px solid #1e293b;font-size:12px;">BALANCE CARRIED FORWARD</td><td style="padding:12px;text-align:right;font-weight:700;border:1px solid #1e293b;font-size:12px;${closingBalance < 0 ? 'color:#fca5a5;' : '#86efac;'}">${formatCurrency(closingBalance)}</td></tr>
            </table>
            <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#475569;padding-bottom:6px;border-bottom:2px solid #e2e8f0;margin-bottom:8px;">Transaction Details</div>
            <table style="width:100%;border-collapse:collapse;font-size:10px;">
                <thead>
                    <tr style="background:#f1f5f9;">
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;text-transform:uppercase;">Date</th>
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;text-transform:uppercase;">Description</th>
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;text-transform:uppercase;">Ref</th>
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;text-transform:uppercase;">Receipt/Debit</th>
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;text-transform:uppercase;">Payment/Credit</th>
                        <th style="padding:8px 6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;text-transform:uppercase;">Balance</th>
                    </tr>
                </thead>
                <tbody>
                    ${txnRows || '<tr><td colspan="6" style="padding:30px;text-align:center;color:#94a3b8;border:1px solid #e2e8f0;">No transactions in this period.</td></tr>'}
                </tbody>
            </table>
            <div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr;gap:40px;font-size:10px;">
                <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
                <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Signature / Date</span></div>
            </div>
            <div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">Generated: ${new Date().toLocaleString()} | ${schoolName} Finance Office.</div>
        </div>`;
        document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate cash book: ' + err.message, { type: 'danger' });
        console.error('generateCashBookStatement error:', err);
    }
}
async function generateLedgerStatement(fromDate, toDate) {
    try {
        console.log('Generating Ledger from', fromDate, 'to', toDate);
        const payments = await dbGetAll('payments').catch(() => []);
        const income = await dbGetAll('income').catch(() => []);
        const expenses = await dbGetAll('expenses').catch(() => []);
        const students = await dbGetAll('students').catch(() => []);
        const staff = await dbGetAll('staff').catch(() => []);
        const expCategories = await dbGetAll('expenseCategories').catch(() => []);
        const incomeCategories = await dbGetAll('incomeCategories').catch(() => []);
        const ledgerRefNo = generateRefNumber('LD');
        const branding = await dbGet('settings', 'branding').catch(() => null);
        const schoolName = branding?.schoolName || 'NET FOUNDATION KENYA';
        const defaultExpCats = [
            { id: 'CAT-SALARY', name: 'Staff Salaries' },
            { id: 'CAT-UTILITIES', name: 'Utilities' },
            { id: 'CAT-MAINTENANCE', name: 'Maintenance' },
            { id: 'CAT-SUPPLIES', name: 'Supplies' },
            { id: 'CAT-TRANSPORT', name: 'Transport' },
            { id: 'CAT-OTHER', name: 'Other Expenses' }
        ];
        const allExpCats = [...defaultExpCats, ...expCategories.filter(c => !defaultExpCats.find(d => d.id === c.id))];
        const defaultIncCats = [
            { id: 'INC-FEE', name: 'Student Fees' },
            { id: 'INC-DONATION', name: 'Donations' },
            { id: 'INC-GRANT', name: 'Grants' },
            { id: 'INC-OTHER', name: 'Other Income' }
        ];
        let html = `<div id="statement-print-area" style="background:#fff;padding:20px;max-width:210mm;margin:0 auto;font-family:'Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;">`;
        html += await generateStatementHeader('LEDGER', ledgerRefNo, fromDate, toDate);
        const periodPayments = payments.filter(p => p.date >= fromDate && p.date <= toDate).sort((a, b) => a.date.localeCompare(b.date));
        let studentTotal = 0;
        const studentTxns = periodPayments.map(p => {
            studentTotal += p.amount;
            const s = students.find(st => st.id === p.studentId);
            return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:4px 6px;font-size:9px;">${formatDate(p.date)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(p.receiptNo || p.id)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(s ? s.name : p.studentId)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(p.method)}</td><td style="padding:4px 6px;text-align:right;font-size:9px;">${formatCurrency(p.amount)}</td><td style="padding:4px 6px;text-align:right;font-size:9px;font-weight:600;">${formatCurrency(studentTotal)}</td></tr>`;
        }).join('');
        html += `<div style="margin-top:16px;page-break-inside:avoid;">
            <div style="font-size:11px;font-weight:700;background:#f1f5f9;padding:8px;border:1px solid #e2e8f0;">STUDENT FEES LEDGER</div>
            <table style="width:100%;border-collapse:collapse;font-size:9px;">
                <thead><tr style="background:#f8fafc;"><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Date</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Receipt No</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Student</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Method</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Amount</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Running Total</th></tr></thead>
                <tbody>${studentTxns || '<tr><td colspan="6" style="padding:20px;text-align:center;color:#94a3b8;">No transactions</td></tr>'}</tbody>
                <tfoot><tr style="background:#fef3c7;font-weight:700;"><td colspan="4" style="padding:8px;border:1px solid #e2e8f0;">TOTAL FEES</td><td style="padding:8px;text-align:right;border:1px solid #e2e8f0;">${formatCurrency(studentTotal)}</td><td style="padding:8px;border:1px solid #e2e8f0;"></td></tr></tfoot>
            </table>
        </div>`;
        for (const cat of allExpCats) {
            const periodExp = expenses.filter(e => e.date >= fromDate && e.date <= toDate && e.categoryId === cat.id).sort((a, b) => a.date.localeCompare(b.date));
            if (periodExp.length === 0) continue;
            let catTotal = 0;
            const catTxns = periodExp.map(e => {
                catTotal += e.amount;
                return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:4px 6px;font-size:9px;">${formatDate(e.date)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(e.receiptRef || e.id)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(e.paidTo || '-')}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml((e.description || '').substring(0,25))}</td><td style="padding:4px 6px;text-align:right;font-size:9px;">${formatCurrency(e.amount)}</td><td style="padding:4px 6px;text-align:right;font-size:9px;font-weight:600;">${formatCurrency(catTotal)}</td></tr>`;
            }).join('');
            html += `<div style="margin-top:16px;page-break-inside:avoid;">
                <div style="font-size:11px;font-weight:700;background:#fef3c7;padding:8px;border:1px solid #e2e8f0;">EXPENSES - ${escapeHtml(cat.name).toUpperCase()}</div>
                <table style="width:100%;border-collapse:collapse;font-size:9px;">
                    <thead><tr style="background:#f8fafc;"><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Date</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Ref</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Paid To</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Description</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Amount</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Total</th></tr></thead>
                    <tbody>${catTxns}</tbody>
                    <tfoot><tr style="background:#fecaca;font-weight:700;"><td colspan="4" style="padding:8px;border:1px solid #e2e8f0;">TOTAL ${escapeHtml(cat.name).toUpperCase()}</td><td style="padding:8px;text-align:right;border:1px solid #e2e8f0;">${formatCurrency(catTotal)}</td><td style="padding:8px;border:1px solid #e2e8f0;"></td></tr></tfoot>
                </table>
            </div>`;
        }
        const salaryExp = expenses.filter(e => e.date >= fromDate && e.date <= toDate && e.categoryId === 'CAT-SALARY').sort((a, b) => a.date.localeCompare(b.date));
        if (salaryExp.length > 0) {
            let salaryTotal = 0;
            const salaryTxns = salaryExp.map(e => {
                salaryTotal += e.amount;
                return `<tr style="border-bottom:1px solid #f1f5f9;"><td style="padding:4px 6px;font-size:9px;">${formatDate(e.date)}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(e.receiptRef || '-')}</td><td style="padding:4px 6px;font-size:9px;">${escapeHtml(e.paidTo || '-')}</td><td style="padding:4px 6px;text-align:right;font-size:9px;">${formatCurrency(e.amount)}</td><td style="padding:4px 6px;text-align:right;font-size:9px;font-weight:600;">${formatCurrency(salaryTotal)}</td></tr>`;
            }).join('');
            html += `<div style="margin-top:16px;page-break-inside:avoid;">
                <div style="font-size:11px;font-weight:700;background:#dbeafe;padding:8px;border:1px solid #e2e8f0;">SALARY PAYMENTS LEDGER</div>
                <table style="width:100%;border-collapse:collapse;font-size:9px;">
                    <thead><tr style="background:#f8fafc;"><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Date</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Ref</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:left;font-size:8px;">Staff Name</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Amount</th><th style="padding:6px;border:1px solid #e2e8f0;text-align:right;font-size:8px;">Total</th></tr></thead>
                    <tbody>${salaryTxns}</tbody>
                    <tfoot><tr style="background:#fecaca;font-weight:700;"><td colspan="3" style="padding:8px;border:1px solid #e2e8f0;">TOTAL SALARIES</td><td style="padding:8px;text-align:right;border:1px solid #e2e8f0;">${formatCurrency(salaryTotal)}</td><td style="padding:8px;border:1px solid #e2e8f0;"></td></tr></tfoot>
                </table>
            </div>`;
        }
        const totalFeeIncome = periodPayments.reduce((s, p) => s + p.amount, 0);
        const totalOtherIncome = income.filter(i => i.date >= fromDate && i.date <= toDate).reduce((s, i) => s + i.amount, 0);
        const totalExpenses = expenses.filter(e => e.date >= fromDate && e.date <= toDate).reduce((s, e) => s + e.amount, 0);
        html += `<div style="margin-top:24px;page-break-inside:avoid;">
            <div style="font-size:12px;font-weight:700;background:#1e293b;color:#fff;padding:10px;text-align:center;">LEDGER SUMMARY</div>
            <table style="width:100%;border-collapse:collapse;font-size:11px;">
                <tr style="background:#f1f5f9;"><td style="padding:10px;border:1px solid #e2e8f0;font-weight:600;">Total Student Fees Received</td><td style="padding:10px;text-align:right;border:1px solid #e2e8f0;color:var(--success);font-weight:600;">${formatCurrency(totalFeeIncome)}</td></tr>
                <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:600;">Total Other Income</td><td style="padding:10px;text-align:right;border:1px solid #e2e8f0;color:var(--info);font-weight:600;">${formatCurrency(totalOtherIncome)}</td></tr>
                <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:600;">Total Expenses</td><td style="padding:10px;text-align:right;border:1px solid #e2e8f0;color:var(--danger);font-weight:600;">(${formatCurrency(totalExpenses)})</td></tr>
                <tr style="background:#dcfce7;font-weight:700;"><td style="padding:12px;border:1px solid #e2e8f0;font-size:12px;">NET POSITION</td><td style="padding:12px;text-align:right;border:1px solid #e2e8f0;font-size:12px;color:var(--success);">${formatCurrency(totalFeeIncome + totalOtherIncome - totalExpenses)}</td></tr>
            </table>
        </div>`;
        html += `<div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:30px;font-size:10px;">
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Prepared By</span><br><span style="font-size:9px;color:#94a3b8;">Accountant / Date</span></div>
            <div style="border-top:1px solid #1a1a2e;padding-top:6px;"><span style="color:#64748b;">Reviewed By</span><br><span style="font-size:9px;color:#94a3b8;">Finance Manager / Date</span></div>
            <div style="border-top:1px solid #1e1a2e;padding-top:6px;"><span style="color:#64748b;">Approved By</span><br><span style="font-size:9px;color:#94a3b8;">Director / Date</span></div>
        </div>
        <div style="margin-top:16px;padding-top:8px;border-top:1px solid #e2e8f0;text-align:center;font-size:8px;color:#94a3b8;">Generated: ${new Date().toLocaleString()} | ${schoolName} Finance Office.</div>
        </div>`;
        document.getElementById('statement-output').innerHTML = html;
    } catch (err) {
        showToast('Failed to generate ledger: ' + err.message, { type: 'danger' });
        console.error('generateLedgerStatement error:', err);
    }
}

// ===== REGION / CENTER / STUDENT DRILL-DOWN =====
function _canAccessRegion(regionId) {
    if (isCoordinator()) {
        const myRegion = getCoordinatorRegionId();
        if (myRegion && myRegion !== regionId) return false;
    }
    return true;
}

function _attendanceRate(att, studentId) {
    const recs = att.filter(a => a.studentId === studentId);
    if (!recs.length) return null;
    const attended = recs.filter(a => a.status === 'present' || a.status === 'late').length;
    return Math.round((attended / recs.length) * 100);
}

async function showRegionDetail(regionId) {
    try {
    if (!_canAccessRegion(regionId)) return showToast('Access denied: this region is outside your scope.', { type: 'danger' });
    const region = await dbGet('regions', regionId);
    if (!region) return showToast('Region not found');
    const centers = await dbGetAll('studyCenters');
    const students = await dbGetAll('students');
    const attendance = await dbGetAll('attendance');
    const payments = await dbGetAll('payments');
    const regionCenters = centers.filter(c => c.regionId === regionId);
    const allStudents = students.filter(s => s.studyCenterId && regionCenters.some(c => c.id === s.studyCenterId));
    let html = `<div style="margin-bottom:12px;font-size:12px;color:var(--text-muted);">Drill-down of <b>${region.name}</b>. Click a center to see its students, attendance and fee status.</div>`;
    html += `<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:14px;">
        <div class="stat-card" style="flex:1;min-width:120px;"><div class="stat-label">Centers</div><div class="stat-value" style="color:var(--accent)">${regionCenters.length}</div></div>
        <div class="stat-card" style="flex:1;min-width:120px;"><div class="stat-label">Students</div><div class="stat-value">${allStudents.length}</div></div>
        <div class="stat-card" style="flex:1;min-width:120px;"><div class="stat-label">Outstanding Fees</div><div class="stat-value" style="color:var(--warning)">${formatCurrency(allStudents.reduce((s, st) => s + (getCachedStudentFee(st) - payments.filter(p => p.studentId === st.id).reduce((a, p) => a + p.amount, 0)), 0))}</div></div>
        <div class="stat-card" style="flex:1;min-width:120px;"><div class="stat-label">Problem Learners</div><div class="stat-value" style="color:var(--danger)">${allStudents.filter(s => s.status !== 'active' || (getCachedStudentFee(s) - payments.filter(p => p.studentId === s.id).reduce((a, p) => a + p.amount, 0)) > 0).length}</div></div>
    </div>`;
    if (!regionCenters.length) {
        html += '<div style="color:var(--text-muted);font-size:12px;padding:10px;">No study centers assigned to this region yet. Edit the region to add centers.</div>';
    } else {
        html += regionCenters.map(c => {
            const cStudents = students.filter(s => s.studyCenterId === c.id);
            const active = cStudents.filter(s => s.status === 'active');
            const rates = cStudents.map(s => _attendanceRate(attendance, s.id)).filter(r => r !== null);
            const avgAtt = rates.length ? Math.round(rates.reduce((a, b) => a + b, 0) / rates.length) : null;
            const outstanding = cStudents.reduce((s, st) => s + (getCachedStudentFee(st) - payments.filter(p => p.studentId === st.id).reduce((a, p) => a + p.amount, 0)), 0);
            const problems = cStudents.filter(s => s.status !== 'active' || (getCachedStudentFee(s) - payments.filter(p => p.studentId === s.id).reduce((a, p) => a + p.amount, 0)) > 0).length;
            const lowAtt = cStudents.filter(s => { const r = _attendanceRate(attendance, s.id); return r !== null && r < 70; }).length;
            return `<div class="event-item" style="flex-direction:column;align-items:flex-start;gap:6px;">
                <div style="display:flex;justify-content:space-between;width:100%;align-items:center;"><span><b>${escapeHtml(c.name)}</b> <span class="badge badge-info">${escapeHtml(c.code)}</span></span><button class="btn btn-primary btn-sm" onclick="event.stopPropagation();showCenterDetail('${c.id}')">🔍 Open</button></div>
                <div style="display:flex;gap:12px;font-size:11px;color:var(--text-muted);flex-wrap:wrap;">
                    <span>👥 ${active.length}/${cStudents.length} active</span>
                    <span>📊 Att: ${avgAtt !== null ? avgAtt + '%' : '—'}</span>
                    <span>💰 ${formatCurrency(outstanding)} due</span>
                    ${lowAtt ? `<span style="color:var(--danger);">⚠️ ${lowAtt} low att</span>` : ''}
                    ${problems ? `<span style="color:var(--danger);">🔴 ${problems} issues</span>` : ''}
                </div>
            </div>`;
        }).join('');
    }
    showModal('Region: ' + region.name, html, null, { maxWidth: '680px' });
    } catch (err) {
        console.error('showRegionDetail error:', err);
        showToast('Could not open region view: ' + err.message, { type: 'danger' });
    }
}

async function showCenterDetail(centerId) {
    try {
    const center = await dbGet('studyCenters', centerId);
    if (!center) return showToast('Center not found');
    if (!_canAccessRegion(center.regionId || '')) return showToast('Access denied: this center is outside your region scope.', { type: 'danger' });
    const region = center.regionId ? await dbGet('regions', center.regionId) : null;
    const students = await dbGetAll('students');
    const attendance = await dbGetAll('attendance');
    const payments = await dbGetAll('payments');
        const cStudents = students.filter(s => (s.studyCenterId || s.campus) === centerId);
        const paidByStudent = {};
        payments.forEach(p => { if (p.studentId) paidByStudent[p.studentId] = (paidByStudent[p.studentId] || 0) + (p.amount || 0); });
        const balOf = (st) => getCachedStudentFee(st) - (paidByStudent[st.id] || 0);
        let html = `<div style="margin-bottom:10px;font-size:12px;color:var(--text-muted);">${region ? 'Region: <b>' + escapeHtml(region.name) + '</b> · ' : ''}${escapeHtml(center.name)} (${escapeHtml(center.code)})</div>`;
        const allOutstanding = cStudents.reduce((s, st) => s + balOf(st), 0);
        html += `<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:14px;">
            <div class="stat-card" style="flex:1;min-width:110px;"><div class="stat-label">Learners</div><div class="stat-value">${cStudents.length}</div></div>
            <div class="stat-card" style="flex:1;min-width:110px;"><div class="stat-label">Outstanding</div><div class="stat-value" style="color:var(--warning)">${formatCurrency(allOutstanding)}</div></div>
            <div class="stat-card" style="flex:1;min-width:110px;"><div class="stat-label">Issues</div><div class="stat-value" style="color:var(--danger)">${cStudents.filter(s => s.status !== 'active' || balOf(s) > 0).length}</div></div>
        </div>`;
        if (!cStudents.length) {
            html += '<div style="color:var(--text-muted);font-size:12px;padding:10px;">No learners enrolled at this center.</div>';
        } else {
            html += `<div style="font-weight:700;font-size:11px;margin-bottom:6px;color:var(--accent);">Learners (click to open full profile)</div>`;
            html += `<div style="max-height:340px;overflow-y:auto;">` + cStudents.map(s => {
                const balance = balOf(s);
                const rate = _attendanceRate(attendance, s.id);
                const flags = [];
                if (s.status !== 'active') flags.push(`<span class="badge badge-warning">${s.status}</span>`);
                if (balance > 0) flags.push(`<span class="badge badge-danger">${formatCurrency(balance)} due</span>`);
                if (rate !== null && rate < 70) flags.push(`<span class="badge badge-danger">${rate}% att</span>`);
                return `<div class="event-item" style="display:flex;justify-content:space-between;align-items:center;gap:8px;cursor:pointer;" onclick="event.stopPropagation();viewStudent('${s.id}')">
                    <div style="min-width:0;"><b>${escapeHtml(s.name)}</b><br><span style="font-size:10px;color:var(--text-muted);">${escapeHtml(s.admissionNumber || s.id)} · ${escapeHtml(s.program || '—')}${rate !== null ? ' · Att ' + rate + '%' : ''}</span></div>
                    <div style="display:flex;gap:4px;flex-shrink:0;">${flags.join('') || '<span class="badge badge-success">ok</span>'}</div>
                </div>`;
            }).join('') + `</div>`;
        }
    showModal('Center: ' + center.name, html, null, { maxWidth: '640px' });
    } catch (err) {
        console.error('showCenterDetail error:', err);
        showToast('Could not open center view: ' + err.message, { type: 'danger' });
    }
}

async function renderRegions() {
    const regions = await dbGetAll('regions');
    const centers = await dbGetAll('studyCenters');
    const users = await dbGetAll('users');
    const students = await dbGetAll('students');
    document.getElementById('regions-overview').innerHTML = regions.length ? regions.map(r => {
        const regionCenters = centers.filter(c => c.regionId === r.id);
        const coordinators = users.filter(u => u.role === 'coordinator' && u.regionId === r.id);
        const activeStudents = students.filter(s => s.status === 'active' && regionCenters.some(c => (s.studyCenterId || s.campus) === c.id));
        return `<div class="event-item" style="flex-direction:column;align-items:flex-start;gap:4px;"><div style="display:flex;justify-content:space-between;width:100%;"><span><b>${r.name}</b></span><div style="display:flex;gap:4px;"><button class="btn btn-primary btn-sm" onclick="showRegionDetail('${r.id}')">🔍 Drill Down</button><button class="btn btn-outline btn-sm" onclick="manageRegionCenters('${r.id}')">📚 Centers</button><button class="btn btn-outline btn-sm" onclick="editRegion('${r.id}')">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteRegion('${r.id}')">Del</button></div></div><div style="display:flex;gap:12px;font-size:11px;color:var(--text-muted);"><span>📚 ${regionCenters.length} center${regionCenters.length !== 1 ? 's' : ''}</span><span>👤 ${coordinators.length} coordinator${coordinators.length !== 1 ? 's' : ''}</span><span>🎓 ${activeStudents.length} student${activeStudents.length !== 1 ? 's' : ''}</span></div>${coordinators.length ? `<div style="font-size:11px;color:var(--accent);margin-top:2px;">Coordinator${coordinators.length > 1 ? 's' : ''}: ${coordinators.map(u => `<span style="display:inline-flex;align-items:center;gap:4px;background:var(--bg-input);border:1px solid var(--border);border-radius:10px;padding:1px 8px;margin:2px 4px 2px 0;">${esc(u.name || u.username)}<button class="btn btn-outline btn-sm" style="padding:0 5px;font-size:9px;margin-left:2px;" onclick="transferCoordinator('${u.username}')">🔄 Transfer</button></span>`).join('')}</div>` : ''}<div style="margin-top:4px;"><button class="btn btn-success btn-sm" onclick="showCoordinatorForm('${r.id}')">➕ Register Coordinator</button></div></div>`;
    }).join('') : '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:10px;">No regions added</div>';
    const settingsList = document.getElementById('regions-list');
    if (settingsList) settingsList.innerHTML = regions.length ? regions.map(r => `<div class="event-item" style="flex-direction:column;align-items:flex-start;gap:2px;"><div style="display:flex;justify-content:space-between;width:100%;"><span><b>${r.name}</b> <span class="badge badge-info">${(centers.filter(c => c.regionId === r.id).length)} centers</span></span><button class="btn btn-outline btn-sm" onclick="editRegion('${r.id}')">Edit</button></div></div>`).join('') : '<div style="color:var(--text-muted);font-size:11px;">No regions</div>';
}

async function showRegionForm(region = null) {
    const isEdit = !!region;
    const content = `<input type="hidden" id="region-edit-id" value="${region ? region.id : ''}">
<div class="form-group"><label>Region Name *</label><input type="text" id="region-name" value="${region ? region.name : ''}" placeholder="e.g., Coast Region"></div>
<div class="form-group"><label>Region ID * (short code, no spaces)</label><input type="text" id="region-code" value="${region ? region.id.replace('REG-', '') : ''}" placeholder="e.g., COAST" maxlength="10" style="text-transform:uppercase;font-weight:600;"></div>`;
    showModal(isEdit ? 'Edit Region' : 'Add Region', content, `<button class="btn btn-primary" onclick="saveRegion()">${isEdit ? 'Update' : 'Save'}</button>`);
}

async function saveRegion() {
    const name = document.getElementById('region-name').value.trim();
    const code = document.getElementById('region-code').value.trim().toUpperCase().replace(/[^A-Z0-9_-]/g, '');
    if (!name) return showToast('Region name required!');
    if (!code) return showToast('Region code required!');
    const editId = document.getElementById('region-edit-id').value;
    const id = editId || 'REG-' + code;
    const region = { id, name, createdAt: editId ? (await dbGet('regions', id)).createdAt : new Date().toISOString() };
    await dbPut('regions', region); closeModal(); await renderRegions(); showToast(editId ? 'Region updated!' : 'Region added!'); logAudit(editId ? 'updated' : 'created', 'region', region);
}

async function editRegion(id) {
    const r = await dbGet('regions', id);
    if (!r) return;
    showRegionForm(r);
}

async function deleteRegion(id) {
    if (!await showConfirm('Confirm', 'Delete region? This will NOT delete its study centers or users.')) return;
    await dbDelete('regions', id); await renderRegions(); showToast('Region deleted'); logAudit('deleted', 'region', { id });
}

async function showCoordinatorForm(regionId) {
    const region = await dbGet('regions', regionId);
    if (!region) return showToast('Region not found');
    const content = `<input type="hidden" id="coord-region" value="${regionId}">
<div class="form-group"><label>Full Name *</label><input type="text" id="coord-name" placeholder="e.g., John Doe"></div>
<div class="form-group"><label>Username *</label><input type="text" id="coord-username" placeholder="e.g., jdoe"></div>
<div class="form-group"><label>Password *</label><input type="password" id="coord-password" placeholder="min 4 characters"></div>
<div class="form-group"><label>Region</label><input type="text" value="${region.name}" disabled style="background:var(--bg-input);color:var(--text-muted);"></div>
<div style="font-size:11px;color:var(--text-muted);">This account will be created as a <b>Coordinator</b> for <b>${region.name}</b>, with access limited to their region's data.</div>`;
    showModal('Register Coordinator — ' + region.name, content, `<button class="btn btn-primary" onclick="saveCoordinator()">Register</button>`);
}

async function saveCoordinator() {
    const regionId = document.getElementById('coord-region').value;
    const name = document.getElementById('coord-name').value.trim();
    const username = document.getElementById('coord-username').value.trim();
    const password = document.getElementById('coord-password').value;
    if (!name || !username || !password) return showToast('All fields required!');
    if (password.length < 4) return showToast('Password must be at least 4 characters!');
    const existing = await dbGet('users', username);
    if (existing) return showToast('Username already taken!');
    const pwHash = await hashPassword(password);
    const user = { username, password: pwHash, name, role: 'coordinator', regionId, createdAt: new Date().toISOString() };
    await dbPut('users', user);
    closeModal(); await renderRegions(); await renderUsers();
    showToast('Coordinator registered!', { type: 'success' });
    logAudit('created', 'coordinator', { username, regionId });
}

async function transferCoordinator(username) {
    const user = await dbGet('users', username);
    if (!user || user.role !== 'coordinator') return showToast('Coordinator not found');
    const regions = await dbGetAll('regions');
    if (regions.length < 2) return showToast('At least two regions are required to transfer');
    const opts = regions.filter(r => r.id !== user.regionId).map(r => `<option value="${r.id}">${r.name}</option>`).join('');
    const content = `<div style="margin-bottom:8px;font-size:12px;color:var(--text-muted);">Transfer <b>${esc(user.name || user.username)}</b> from their current region to a new region. Their access will be scoped to the new region immediately.</div>
<div class="form-group"><label>Current Region</label><input type="text" value="${window._regionsCache?.find(r => r.id === user.regionId)?.name || user.regionId || '—'}" disabled style="background:var(--bg-input);color:var(--text-muted);"></div>
<div class="form-group"><label>New Region *</label><select id="coord-transfer-region">${opts}</select></div>`;
    showModal('Transfer Coordinator', content, `<button class="btn btn-primary" onclick="confirmTransferCoordinator('${username}')">Transfer</button>`);
}

async function confirmTransferCoordinator(username) {
    const newRegionId = document.getElementById('coord-transfer-region').value;
    if (!newRegionId) return showToast('Select a new region!');
    const user = await dbGet('users', username);
    if (!user) return;
    user.regionId = newRegionId;
    await dbPut('users', user);
    closeModal(); await renderRegions(); await renderUsers();
    showToast('Coordinator transferred!', { type: 'success' });
    logAudit('updated', 'coordinator-transfer', { username, regionId: newRegionId });
}

async function manageRegionCenters(regionId) {
    const region = await dbGet('regions', regionId);
    if (!region) return showToast('Region not found');
    const allCenters = await dbGetAll('studyCenters');
    const regionCenters = allCenters.filter(c => c.regionId === regionId);
    const unassigned = allCenters.filter(c => !c.regionId);
    const otherRegionCenters = allCenters.filter(c => c.regionId && c.regionId !== regionId);
    let html = `<div style="margin-bottom:10px;font-size:12px;color:var(--text-muted);">Assign or unassign centers to <b>${region.name}</b></div>`;
    if (regionCenters.length) {
        html += `<div style="font-weight:700;font-size:11px;margin-bottom:4px;color:var(--accent);">Assigned (${regionCenters.length})</div>`;
        html += regionCenters.map(c => `<div class="event-item" style="display:flex;justify-content:space-between;align-items:center;"><span><b>${c.name}</b> <span class="badge badge-info">${c.code}</span></span><button class="btn btn-danger btn-sm" onclick="unassignCenterFromRegion('${c.id}','${regionId}')">Remove</button></div>`).join('');
    }
    if (unassigned.length) {
        html += `<div style="font-weight:700;font-size:11px;margin:8px 0 4px;color:var(--warning);">Unassigned (${unassigned.length})</div>`;
        html += unassigned.map(c => `<div class="event-item" style="display:flex;justify-content:space-between;align-items:center;"><span><b>${c.name}</b> <span class="badge badge-info">${c.code}</span></span><button class="btn btn-success btn-sm" onclick="assignCenterToRegion('${c.id}','${regionId}')">Assign</button></div>`).join('');
    }
    if (!regionCenters.length && !unassigned.length) html += '<div style="color:var(--text-muted);font-size:12px;">No study centers exist. Create one in Settings first.</div>';
    if (otherRegionCenters.length) {
        html += `<div style="font-weight:700;font-size:11px;margin:8px 0 4px;color:var(--text-muted);">Assigned to Other Regions (${otherRegionCenters.length})</div>`;
        html += otherRegionCenters.map(c => `<div class="event-item" style="display:flex;justify-content:space-between;align-items:center;"><span><b>${c.name}</b> <span class="badge badge-info">${c.code}</span></span><button class="btn btn-outline btn-sm" onclick="assignCenterToRegion('${c.id}','${regionId}')">Move Here</button></div>`).join('');
    }
    showModal(`Centers — ${region.name}`, html);
}

async function assignCenterToRegion(centerId, regionId) {
    const center = await dbGet('studyCenters', centerId);
    if (!center) return;
    center.regionId = regionId;
    await dbPut('studyCenters', center);
    showToast(`${center.name} assigned to region`);
    manageRegionCenters(regionId);
    renderRegions();
}

async function unassignCenterFromRegion(centerId, regionId) {
    const center = await dbGet('studyCenters', centerId);
    if (!center) return;
    center.regionId = '';
    await dbPut('studyCenters', center);
    showToast(`${center.name} unassigned`);
    manageRegionCenters(regionId);
    renderRegions();
}

// ===================== INTERNAL MESSAGING (staff + coordinators) =====================
async function renderMessages() {
    const currentUser = JSON.parse(sessionStorage.getItem('currentUser') || '{}');
    if (!currentUser.username) return;
    const messages = await dbGetAll('messages');
    const users = await dbGetAll('users');
    const staff = users.filter(u => u.role !== 'student' && u.username !== currentUser.username);
    const myMessages = messages.filter(m => m.sender === currentUser.username || m.recipient === currentUser.username);
    const conversations = {};
    myMessages.forEach(m => {
        const other = m.sender === currentUser.username ? m.recipient : m.sender;
        if (!conversations[other]) conversations[other] = { username: other, last: m, unread: 0 };
        if (m.timestamp > conversations[other].last.timestamp) conversations[other].last = m;
        if (!m.read && m.recipient === currentUser.username) conversations[other].unread++;
    });
    const convList = Object.values(conversations).sort((a, b) => b.last.timestamp - a.last.timestamp);
    const convEl = document.getElementById('messages-conversations');
    if (convEl) {
        convEl.innerHTML = convList.length ? convList.map(c => {
            const u = users.find(x => x.username === c.username);
            const name = u ? (u.name || u.username) : c.username;
            return `<div class="event-item" style="cursor:pointer;${c.unread ? 'background:var(--bg-input);border-left:3px solid var(--accent);' : ''}" onclick="openConversation('${c.username}')">
                <div style="display:flex;justify-content:space-between;align-items:center;"><b style="font-size:13px;">${esc(name)}</b>${c.unread ? `<span class="badge badge-danger" style="font-size:9px;">${c.unread}</span>` : ''}</div>
                <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:240px;">${esc((c.last.sender === currentUser.username ? 'You: ' : '') + (c.last.body || ''))}</div>
            </div>`;
        }).join('') : '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:10px;">No conversations yet</div>';
    }
    const threadEl = document.getElementById('messages-thread');
    if (threadEl && !threadEl.dataset.activeConv) {
        threadEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-muted);font-size:13px;text-align:center;padding:20px;">Select a conversation or click <b>New Message</b> to start one.</div>';
    }
}

async function openConversation(username) {
    const currentUser = JSON.parse(sessionStorage.getItem('currentUser') || '{}');
    if (!currentUser.username) return;
    const users = await dbGetAll('users');
    const other = users.find(u => u.username === username);
    const threadEl = document.getElementById('messages-thread');
    if (threadEl) threadEl.dataset.activeConv = username;
    const messages = (await dbGetAll('messages'))
        .filter(m => (m.sender === currentUser.username && m.recipient === username) || (m.sender === username && m.recipient === currentUser.username))
        .sort((a, b) => a.timestamp - b.timestamp);
    // mark read
    for (const m of messages) {
        if (!m.read && m.recipient === currentUser.username) { m.read = true; await dbPut('messages', m); }
    }
    const name = other ? (other.name || other.username) : username;
    let html = `<div style="border-bottom:1px solid var(--border);padding-bottom:10px;margin-bottom:12px;">
        <div style="font-weight:700;font-size:15px;color:var(--accent);">${esc(name)}</div>
        <div style="font-size:11px;color:var(--text-muted);">${other ? other.role : ''}</div>
    </div>`;
    html += messages.length ? messages.map(m => {
        const mine = m.sender === currentUser.username;
        return `<div style="display:flex;${mine ? 'justify-content:flex-end;' : ''}margin-bottom:10px;">
            <div style="max-width:75%;padding:8px 12px;border-radius:12px;font-size:13px;line-height:1.4;${mine ? 'background:var(--accent);color:#fff;border-bottom-right-radius:2px;' : 'background:var(--bg-input);border-bottom-left-radius:2px;'}">
                <div>${esc(m.body)}</div>
                <div style="font-size:9px;opacity:0.7;margin-top:3px;text-align:${mine ? 'right' : 'left'};">${new Date(m.timestamp).toLocaleString()}</div>
            </div>
        </div>`;
    }).join('') : '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:10px;">No messages yet. Say hello!</div>';
    html += `<div style="margin-top:10px;display:flex;gap:6px;">
        <input type="text" id="msg-reply" class="form-control" placeholder="Type a message..." onkeydown="if(event.key==='Enter')sendMessage('${username}')" style="flex:1;">
        <button class="btn btn-primary btn-sm" onclick="sendMessage('${username}')">Send</button>
    </div>`;
    if (threadEl) threadEl.innerHTML = html;
    renderMessages();
}

async function sendMessage(recipient) {
    const currentUser = JSON.parse(sessionStorage.getItem('currentUser') || '{}');
    const input = document.getElementById('msg-reply');
    if (!input) return;
    const body = input.value.trim();
    if (!body) return;
    const msg = { id: 'MSG-' + Date.now(), sender: currentUser.username, recipient, body, timestamp: Date.now(), read: false };
    await dbPut('messages', msg);
    logAudit('sent', 'message', { recipient });
    openConversation(recipient);
}

function showComposeMessage() {
    const currentUser = JSON.parse(sessionStorage.getItem('currentUser') || '{}');
    if (!currentUser.username) return;
    dbGetAll('users').then(users => {
        const staff = users.filter(u => u.role !== 'student' && u.username !== currentUser.username);
        const opts = staff.map(u => `<option value="${u.username}">${esc(u.name || u.username)} (${u.role})</option>`).join('');
        const content = `<div class="form-group"><label>To</label><select id="msg-to">${opts}</select></div>
        <div class="form-group"><label>Message</label><textarea id="msg-body" rows="4" placeholder="Write your message..."></textarea></div>`;
        showModal('New Message', content, `<button class="btn btn-primary" onclick="sendComposedMessage()">Send</button>`);
    });
}

async function sendComposedMessage() {
    const currentUser = JSON.parse(sessionStorage.getItem('currentUser') || '{}');
    const to = document.getElementById('msg-to').value;
    const body = document.getElementById('msg-body').value.trim();
    if (!to || !body) return showToast('Recipient and message required!');
    const msg = { id: 'MSG-' + Date.now(), sender: currentUser.username, recipient: to, body, timestamp: Date.now(), read: false };
    await dbPut('messages', msg);
    closeModal();
    await renderMessages();
    await openConversation(to);
    showToast('Message sent!', { type: 'success' });
    logAudit('sent', 'message', { recipient: to });
}

// Bootstrap: auth.js and app.js both throw SyntaxErrors (let redeclarations) preventing their init() calls,
// so we call init() directly here instead.
init().catch(function(e) { console.error('init bootstrap failed:', e); });

document.addEventListener('DOMContentLoaded', function() {
    if (typeof loadPayrollStaffSelect === 'function') loadPayrollStaffSelect();
    document.getElementById('notif-bell')?.addEventListener('click', function(e) {
        e.preventDefault();
        e.stopPropagation();
        if (typeof toggleNotificationDropdown === 'function') toggleNotificationDropdown();
    });
    document.addEventListener('click', function(e) {
        if (window.notifDropdownOpen && !e.target.closest('.notif-dropdown') && e.target.id !== 'notif-bell') {
            if (typeof closeNotifDropdown === 'function') closeNotifDropdown();
        }
    });
});
